func TestGetActiveEBSAccount(t *testing.T) {
	testCases := []struct {
		system     string
		status     string
		hasAccount bool
	}{
		{system: frcpo.SystemEBS, status: frcpo.AccountStatusActive, hasAccount: true},
		{system: frcpo.SystemEBS, status: frcpo.AccountStatusInactive, hasAccount: false},
		{system: frcpo.SystemMSSL, status: frcpo.AccountStatusActive, hasAccount: false},
		{system: frcpo.SystemMSSL, status: frcpo.AccountStatusInactive, hasAccount: false},
	}
	for _, tc := range testCases {
		tc := tc
		t.Run(fmt.Sprintf("%v - %v", tc.system, tc.status), func(t *testing.T) {
			t.Parallel()
			premise := PremisesType{
				Accounts: []AccountsType{
					{
						AccountNumber: "accountNo",
						AccountStatus: tc.status,
						System:        tc.system,
					},
				},
			}

			p, ok := premise.GetActiveEBSAccount()
			require.Equal(t, tc.hasAccount, ok)
			require.NotNil(t, p)
		})
	}
}

func TestGetBPDetails(t *testing.T) {
	testCases := []struct {
		bpNumber     string
		hasBPDetails bool
	}{
		{"VALID", true},
		{"INVALID", false},
	}

	for _, tc := range testCases {
		t.Run(fmt.Sprintf("%t", tc.hasBPDetails), func(t *testing.T) {
			// Given:
			given := Details{
				BpNumbers: []BpNumbersType{
					{BpNumber: tc.bpNumber},
				},
			}

			// When:
			result, ok := given.GetBPDetails("VALID")

			// Then:
			require.Equal(t, tc.hasBPDetails, ok)
			if tc.hasBPDetails {
				require.Equal(t, tc.bpNumber, result.BpNumber)
			} else {
				require.Equal(t, BpNumbersType{}, result)
			}

		})
	}
}

func TestGetEBSAccount(t *testing.T) {
