func TestIsPremiseOwnerOrSharedUserWithFullAccess(t *testing.T) {
	testCases := []struct {
		name          string
		givenDetails  *Details
		expectedError error
	}{
		{
			name: "success with is premise owner",
			givenDetails: &Details{
				Premises: []PremisesType{
					{
						ID: "premiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"},
						SharedResourceDetails: SharedResourceDetailsType{Owner: true},
					},
				},
			},
		},
		{
			name: "error by is not premise owner and without shared user",
			givenDetails: &Details{
				Premises: []PremisesType{
					{
						ID: "premiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"},
						SharedResourceDetails: SharedResourceDetailsType{Owner: false},
					},
				},
			},
			expectedError: ErrPremiseUnauthorized,
		},
		{
			name: "error by shared user and does not have full access",
			givenDetails: &Details{
				JWT: authc.JWTClaims{
					Sub: "iamid",
				},
				Premises: []PremisesType{
					{
						ID: "premiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"},
						SharedResourceDetails: SharedResourceDetailsType{
							Owner: false,
							Users: []SharedResourceUserType{
								{
									IamID:      "iamid",
									FullAccess: false,
								},
								{
									IamID:      "iamid1",
									FullAccess: true,
								},
							},
						},
					},
				},
			},
			expectedError: ErrPremiseUnauthorized,
		},
		{
			name: "success with shared user and full access",
			givenDetails: &Details{
				JWT: authc.JWTClaims{
					Sub: "iamid",
				},
				Premises: []PremisesType{
					{
						ID: "premiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"},
						SharedResourceDetails: SharedResourceDetailsType{
							Owner: false,
							Users: []SharedResourceUserType{
								{
									IamID:      "iamid",
									FullAccess: true,
								},
								{
									IamID:      "iamid1",
									FullAccess: false,
								},
							},
						},
					},
				},
			},
		},
		{
			name: "success with 1 premise is owner, 1 premise isn't the owner and with full access",
			givenDetails: &Details{
				JWT: authc.JWTClaims{
					Sub: "iamid",
				},
				Premises: []PremisesType{
					{
						ID: "premiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"},
						SharedResourceDetails: SharedResourceDetailsType{
							Owner: true,
						},
					},
					{
						ID: "premiseid_2", ContestableDetails: ContestableDetailsType{ContestableType: "something2"},
						SharedResourceDetails: SharedResourceDetailsType{
							Owner: false,
							Users: []SharedResourceUserType{
								{
									IamID:      "iamid",
									FullAccess: true,
								},
								{
									IamID:      "iamid1",
									FullAccess: true,
								},
							},
						},
					},
				},
			},
		},
		{
			name: "success with 1 premise is owner, 1 premise isn't the owner and with does not have full access",
			givenDetails: &Details{
				JWT: authc.JWTClaims{
					Sub: "iamid",
				},
				Premises: []PremisesType{
					{
						ID: "premiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"},
						SharedResourceDetails: SharedResourceDetailsType{
							Owner: true,
						},
					},
					{
						ID: "premiseid_2", ContestableDetails: ContestableDetailsType{ContestableType: "something2"},
						SharedResourceDetails: SharedResourceDetailsType{
							Owner: false,
							Users: []SharedResourceUserType{
								{
									IamID:      "iamid",
									FullAccess: false,
								},
								{
									IamID:      "iamid1",
									FullAccess: false,
								},
							},
						},
					},
				},
			},
		},
	}

	for _, tc := range testCases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			// Given:
			given := "premiseid"
			// When:
			result, err := tc.givenDetails.IsPremiseOwnerOrSharedUserWithFullAccess(given)

			// Then:
			if tc.expectedError != nil {
				require.Equal(t, ErrPremiseUnauthorized, err)
				require.EqualValues(t, PremisesType{}, result)
			} else {
				require.NoError(t, err)
				require.Equal(t, given, result.ID)
				require.Equal(t, "something", result.ContestableDetails.ContestableType)
			}
		})
	}
}

