package usage

import (
	"context"
	"os"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/numutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/utilities"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/service/consumption"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/broker/historicalconsumptionbroker"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/broker/peercomparisonbroker"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs/peercomparison"
	"github.com/pkg/errors"
	"golang.org/x/sync/errgroup"
)

// asyncRetrievePeerComparison retrieves a premises's peer comparison data
func asyncRetrievePeerComparison(ctx context.Context, g *errgroup.Group, p bp.PremisesType) chan ChartsResponse {
	out := make(chan ChartsResponse, 1)

	g.Go(func() error {
		defer close(out)
		var result ChartsResponse
		var err error
		if isPeerComparisonWithContestableEnabled() {
			result, err = retrievePeerComparisonWithContestable(ctx, p)
		} else {
			result, err = retrievePeerComparison(ctx, p)
		}
		if err != nil {
			return err
		}
		out <- result
		return nil
	})
	return out
}

// isPeerComparisonWithContestableEnabled returns true if peer comparison of contestable account is enabled
func isPeerComparisonWithContestableEnabled() bool {
	return os.Getenv("ENABLE_PEER_COMPARISON_FOR_CONTESTABLE_ELEC_ACCOUNTS") == "1"
}

// retrievePeerComparisonWithContestable retrieve peer comparison with contestable account
func retrievePeerComparisonWithContestable(ctx context.Context, p bp.PremisesType) (ChartsResponse, error) {
	logger := loglib.GetLogger(ctx)
	logger.Infof("[retrievePeerComparisonWithContestable] retrieve peer comparison with contestable account")
	var result ChartsResponse
	account, ok := p.GetEBSOrMSSLAccount()
	if !ok {
		return ChartsResponse{}, bp.ErrDetailsNoAccounts
	}

	g := &errgroup.Group{}
	// Retrieve peer comparison of EBS accounts
	respChan, err := asyncPeerComparison(ctx, g, p, account.AccountNumber, account.System)
	if err != nil {
		return ChartsResponse{}, err
	}
	// Retrieve peer comparison of MSSL contestable accounts
	var msslResponseChan chan peercomparison.Response
	var msslResponse peercomparison.Response
	if account.System == frcpo.SystemEBS {
		if msslAccNo := p.ContestableDetails.AccountNumber; msslAccNo != "" {
			msslResponseChan, err = asyncPeerComparison(ctx, g, p, msslAccNo, frcpo.SystemMSSL)
			if err != nil {
				return ChartsResponse{}, err
			}

			if err := g.Wait(); err != nil {
				return ChartsResponse{}, err
			}
			msslResponse = <-msslResponseChan
		}
	}

	if err := g.Wait(); err != nil {
		return ChartsResponse{}, err
	}
	resp := <-respChan

	result.PremiseType = resp.Premisetype.String
	// Iterate over utility types
	for _, ut := range resp.Utilitydetails.Array {
		utType := utilities.TypeLookup[ut.Utilitytype.String]

		// Iterate over data points in each utility type
		data := []DataType{}
		for _, billingDetailsItem := range ut.Billingdetails.Array {
			// Create data point
			d, err := fromPCBillingdetailsType(utType, billingDetailsItem)
			if err != nil {
				// Report errors to Sentry
				reportErrors(err, account.AccountNumber, "", "")
				// Skip invalid data format
				continue
			}
			data = append(data, d)
		}

		switch utType {
		case utilities.TypeElectric:
			result.Elec.ComparisonType = ut.Comparisonarea.String
			result.Elec.ComparisonMessage = ut.Amountmsg.String
			result.Elec.ComparisonMessageType = ut.Amountmsgflag.String
			result.Elec.Data = data
		case utilities.TypeGas:
			result.Gas.ComparisonType = ut.Comparisonarea.String
			result.Gas.ComparisonMessage = ut.Amountmsg.String
			result.Gas.ComparisonMessageType = ut.Amountmsgflag.String
			result.Gas.Data = data
		case utilities.TypeWater:
			result.Water.ComparisonType = ut.Comparisonarea.String
			result.Water.ComparisonMessage = ut.Amountmsg.String
			result.Water.ComparisonMessageType = ut.Amountmsgflag.String
			result.Water.Data = data
		default:
			// Report errors to Sentry
			reportErrors(errors.Errorf("unrecognized utility type %s", ut.Utilitytype.String), account.AccountNumber, "", "")
			// Skip unrecognized utility type
			continue
		}
	}

	if account.System == frcpo.SystemEBS {
		if msslAccNo := p.ContestableDetails.AccountNumber; msslAccNo != "" {
			if ok := validatePeercomparisonResponse(historicalconsumptionbroker.UtilityTypeElec, msslResponse); ok {
				result.Elec.Data, err = mergePeerComparisonForMSSLElecData(result.Elec.Data, msslResponse, account.AccountNumber)
				if err != nil {
					return ChartsResponse{}, err
				}
			}
		}
	}

	return result, nil
}

// asyncPeerComparison is a helper function that runs a peer comparison request
func asyncPeerComparison(ctx context.Context, g *errgroup.Group, p bp.PremisesType, accountNumber, system string) (chan peercomparison.Response, error) {
	out := make(chan peercomparison.Response, 2)
	g.Go(func() error {
		defer close(out)
		// Retrieve peer comparison
		resp, err := peercomparisonbroker.MakeRequest(ctx, system,
			peercomparison.Request{
				Saccountno:  accountNumber,
				Flag:        "PEERCOMP",
				Designgroup: "PC2",
			},
		)
		if err != nil {
			return err
		}

		out <- resp
		return nil
	})

	return out, nil
}

// validatePeercomparisonResponse validate peer comparison response by utility type
func validatePeercomparisonResponse(utilityType string, msslResponse peercomparison.Response) bool {
	valueExist := false
	for _, ut := range msslResponse.Utilitydetails.Array {
		if ut.Utilitytype.String != utilityType {
			continue
		}
		for _, billingDetailsItem := range ut.Billingdetails.Array {
			if billingDetailsItem.Averagekwh.String != "" || billingDetailsItem.Efficientkwh.String != "" {
				valueExist = true
				break
			}
		}
	}

	return valueExist
}

// mergePeerComparisonForMSSLElecData merge peer comparison data for MSSL electric data
func mergePeerComparisonForMSSLElecData(ebsElecData []DataType, msslResponse peercomparison.Response, accountNumber string) ([]DataType, error) {
	// convert EBS electric data to map in order to merging
	lookup := map[time.Time]DataType{}
	for _, data := range ebsElecData {
		lookup[data.Period] = data
	}
	// create MSSL electric data from MSSL response
	msslElecData := []DataType{}
	for _, ut := range msslResponse.Utilitydetails.Array {
		utType := utilities.TypeLookup[ut.Utilitytype.String]
		if utType == utilities.TypeElectric {
			for _, billingDetailsItem := range ut.Billingdetails.Array {
				// Create data point
				d, err := fromPCBillingdetailsType(utType, billingDetailsItem)
				if err != nil {
					// Report errors to Sentry
					reportErrors(err, accountNumber, "", "")
					// Skip invalid data format
					continue
				}
				msslElecData = append(msslElecData, d)
			}
		}
	}
	// merge with MSSL electric data into EBS electric data
	result := ebsElecData
	for _, data := range msslElecData {
		if _, ok := lookup[data.Period]; !ok {
			result = append(result, data)
		}
	}

	return result, nil
}

// retrievePeerComparison retrieves a premises's peer comparison data
func retrievePeerComparison(ctx context.Context, p bp.PremisesType) (ChartsResponse, error) {
	logger := loglib.GetLogger(ctx)
	logger.Infof("[retrievePeerComparison] retrieve peer comparison without contestable account")
	var result ChartsResponse
	account, ok := p.GetEBSOrMSSLAccount()
	if !ok {
		return ChartsResponse{}, bp.ErrDetailsNoAccounts
	}

	// Retrieve peer comparison
	resp, err := peercomparisonbroker.MakeRequest(ctx, account.System,
		peercomparison.Request{
			Saccountno:  account.AccountNumber,
			Flag:        "PEERCOMP",
			Designgroup: "PC2",
		})

	if err != nil {
		return ChartsResponse{}, err
	}
	// Set premises type
	result.PremiseType = resp.Premisetype.String

	// Iterate over utility types
	for _, ut := range resp.Utilitydetails.Array {
		utType := utilities.TypeLookup[ut.Utilitytype.String]

		// Iterate over data points in each utility type
		data := []DataType{}
		for _, it := range ut.Billingdetails.Array {
			// Create data point
			d, err := fromPCBillingdetailsType(utType, it)
			if err != nil {
				// Report errors to Sentry
				reportErrors(err, account.AccountNumber, "", "")
				// Skip invalid data format
				continue
			}
			data = append(data, d)
		}

		switch utType {
		case utilities.TypeElectric:
			result.Elec.ComparisonType = ut.Comparisonarea.String
			result.Elec.ComparisonMessage = ut.Amountmsg.String
			result.Elec.ComparisonMessageType = ut.Amountmsgflag.String
			result.Elec.Data = data
		case utilities.TypeGas:
			result.Gas.ComparisonType = ut.Comparisonarea.String
			result.Gas.ComparisonMessage = ut.Amountmsg.String
			result.Gas.ComparisonMessageType = ut.Amountmsgflag.String
			result.Gas.Data = data
		case utilities.TypeWater:
			result.Water.ComparisonType = ut.Comparisonarea.String
			result.Water.ComparisonMessage = ut.Amountmsg.String
			result.Water.ComparisonMessageType = ut.Amountmsgflag.String
			result.Water.Data = data
		default:
			// Report errors to Sentry
			reportErrors(errors.Errorf("unrecognized utility type %s", ut.Utilitytype.String), account.AccountNumber, "", "")
			// Skip unrecognized utility type
			continue
		}
	}
	return result, nil
}

// fromPCBillingdetailsType creates a DataType from raw peer comparison BillingdetailsType
func fromPCBillingdetailsType(utType string, item peercomparison.BillingdetailsType) (DataType, error) {
	average, err := numutil.ParsePrettyFloat(item.Averagekwh.String, 64)
	if err != nil {
		return DataType{}, err
	}
	efficient, err := numutil.ParsePrettyFloat(item.Efficientkwh.String, 64)
	if err != nil {
		return DataType{}, err
	}
	timestamp, err := consumption.ExtractBillingMonth(item.Billdate.String)
	if err != nil {
		return DataType{}, err
	}

	return DataType{
		Period: timestamp,
		Unit:   utilities.TypeUnitLookup[utType],
		PeerComparison: PeerComparisonType{
			Average:   average,
			Efficient: efficient,
		},
		// Status, Unit, Consumption - @see fromHCBillingdetailsType
	}, nil
}

