func TestRetrieveEMDS_Weekly(t *testing.T) {
	testCaseScenarios := []struct {
		name                           string
		accountNos                     []string
		start                          time.Time
		end                            time.Time
		mockAMIHalfHourlyByDayResponse emds.AMIHalfHourlyByDayResponse
		expResult                      ResponseGroupMap
	}{
		{
			name:       "success",
			accountNos: []string{"ACC1", "ACC2"},
			start:      timeutil.Date(2024, 9, 9, 0, 0),
			end:        timeutil.Date(2024, 9, 15, 0, 0),
			mockAMIHalfHourlyByDayResponse: emds.AMIHalfHourlyByDayResponse{
				AccountsList: []emds.AMIHalfHourlyByDayAccountsList{
					{
						AccountNumber: "ACC1",
						HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
							{Date: "2024-09-09", DailySumValue: 20},
							{Date: "2024-09-11", DailySumValue: 20},
							{Date: "2024-09-13", DailySumValue: 20},
							{Date: "INVALID", DailySumValue: 20},
							{Date: "2024-09-14", DailySumValue: 0},
						},
					},
					{
						AccountNumber: "ACC2",
						HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
							{Date: "2024-09-09", DailySumValue: 20},
							{Date: "2024-09-11", DailySumValue: 20},
							{Date: "2024-09-13", DailySumValue: 20},
							{Date: "INVALID", DailySumValue: 20},
							{Date: "2024-09-14", DailySumValue: 0},
						},
					},
				},
			},
			expResult: ResponseGroupMap{
				"2024-09-09T00:00:00+08:00": DataPointGroupMap{
					"2024-09-09T00:00:00+08:00": DataType{Date: "2024-09-09T00:00:00+08:00", Consumption: 40.0},
					"2024-09-11T00:00:00+08:00": DataType{Date: "2024-09-11T00:00:00+08:00", Consumption: 40.0},
					"2024-09-13T00:00:00+08:00": DataType{Date: "2024-09-13T00:00:00+08:00", Consumption: 40.0},
					"2024-09-14T00:00:00+08:00": DataType{Date: "2024-09-14T00:00:00+08:00", Consumption: 0.0},
				},
			},
		},
	}
	for _, tc := range testCaseScenarios {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			// Mocks
			ctx = emds.MockAMIHalfHourlyByDay(ctx, nil, tc.mockAMIHalfHourlyByDayResponse, nil)
			//When
			result, err := retrieveEMDS(ctx, tc.accountNos, tc.start, tc.end, ResponseGroupedByWeek)

			// Then:
			require.NoError(t, err)
			require.Equal(t, len(tc.expResult), len(result))
			require.Equal(t, tc.expResult, result)
		})
	}
