package bp

import "sort"

// sortPremises sorts the premises list by owner first then address alphabetically
//
// Sort logic by:
// 1. Owner first
// 2. Active first
// 3. Address in alphabetical ascending order
func sortPremises(p []PremisesType) []PremisesType {
	sort.SliceStable(p, func(i, j int) bool {
		if p[i].SharedResourceDetails.Owner == p[j].SharedResourceDetails.Owner {
			if p[i].Active == p[j].Active {
				// 3. Address in ascending order
				return p[i].Address < p[j].Address
			}
			// 2. Active first
			return p[i].Active && !p[j].Active
		}
		// 1. Owner first
		return p[i].SharedResourceDetails.Owner && !p[j].SharedResourceDetails.Owner
	})
	return p
}

// sortAccounts sorts the accounts list by account status, system, and account number
//
// Sort logic by:
// 1. Account's status in alphabetical ascending order (i.e. Active, Inactive, Prov)
// 2. Account's system in alphabetical ascending order (i.e. EBS, MSSL)
// 3. Account's account number in descending order (The higher the account number, the more recent in EBS/MSSL)
func sortAccounts(a []AccountsType) []AccountsType {
	sort.Slice(a, func(i, j int) bool {
		if a[i].AccountStatus == a[j].AccountStatus {
			if a[i].System == a[j].System {
				// 3. Account number in descending order
				return a[i].AccountNumber > a[j].AccountNumber
			}
			// 2. Ascending order (EBS before MSSL)
			return a[i].System < a[j].System
		}
		// 1. Status in ascending order
		// (Active before Inactive)
		return a[i].AccountStatus < a[j].AccountStatus
	})
	return a
}

