)

func GetDistrictConsumption(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	// Extract query params
	params := r.URL.Query()
	districtID := params.Get("id")
	if err := validator.DistrictValidate(districtID); err != nil {
		return web.WithStack(err)
	}
	year := params.Get("year")
	if year == "" {
		year = defaultYear
	}
	yearParsedToInt, err := validator.YearValidate(year)
	if err != nil {
		return web.WithStack(err)
	}
	energyType, err := TypeValidate(params.Get("type"))
	if err != nil {
		return web.WithStack(err)
	}

	// historical year is determined by current year minus 2
	historicalYear := timeutil.NowSGT().AddDate(-2, 0, 0).Year()

	var resp interface{}
	if isGreenGoalsDistrictTestingEnabled() {
		resp = mockData(energyType, districtID)
	} else {
		districtCode := formatDictrictCode(districtID)
		startMonth, endMonth := timeutil.GetStartAndEndMonthByYear(yearParsedToInt)
		var results greengoals.DistrictConsumption

		// TODO remove QA testing after end-point is verified in QA env
		if yearParsedToInt <= historicalYear || (isQAEnv() && yearParsedToInt == 2021) {
			// process to district consumption request for year that is equal or smaller than current year - 2
			results, err = greengoals.GetDistrictConsumptionHistoricalByType(ctx, districtCode, startMonth, endMonth, energyType)
			if err != nil {
				return web.NewError(ErrDistrictConsumptionHistoricalRetrieve, err.Error())
			}
		} else {
			results, err = greengoals.GetDistrictConsumptionByType(ctx, districtCode, startMonth, endMonth, energyType)
			if err != nil {
				return web.NewError(ErrDistrictConsumptionRetrieve, err.Error())
			}
		}

		// Prepare response
		resp, err = translateToDistrictConsumptionResponse(results, energyType)
		if err != nil {
			return web.NewError(ErrDistrictConsumptionResponses, err.Error())
		}
	}

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

func formatDictrictCode(districtID string) string {
	districtCode := strings.Replace(districtID, "D", "", -1)
	if len(districtCode) == 1 {
		return "0" + districtCode
	}

	return districtCode
}

// translateToDistrictConsumptionResponse convert district consumption data to district consumption response
func translateToDistrictConsumptionResponse(results greengoals.DistrictConsumption, energyType string) (interface{}, error) {
	districtConsumption := DistrictConsumption{
		Unit:                            results.Unit,
		Month:                           results.Month,
		ConsumptionPercentageDifference: results.ConsumptionPercentageDifference,
	}

	for _, consumptionData := range results.Data {
		periodTime, err := timeutil.ParseDatetimeOrTime(consumptionData.Period + "01000000")
		if err != nil {
			return DistrictConsumption{}, err
		}

		districtConsumptionData := DistrictConsumptionData{
			Consumption:     consumptionData.Consumption,
			Period:          periodTime.Format(time.RFC3339),
			DistrictAverage: consumptionData.DistrictAverage,
			Efficient:       consumptionData.Efficient,
		}

		districtConsumption.Data = append(districtConsumption.Data, districtConsumptionData)
	}

	switch energyType {
	case Water.String():
		return DistrictWaterConsumptionResponse{
			Water: districtConsumption,
		}, nil
	default:
		return DistrictElecConsumptionResponse{
			Elec: districtConsumption,
		}, nil
	}
}

func isGreenGoalsDistrictTestingEnabled() bool {
	return os.Getenv("GREEN_GOALS_ENABLE_DISTRICT_TEST") == "1"
}

func mockData(enType, districtID string) interface{} {
	switch enType {
	case Water.String():
		result := DistrictWaterConsumptionResponse{
			Water: DistrictConsumption{
				Unit:                            greengoals.CuMUnitOfMeasurement,
				Month:                           "May 2022",
				ConsumptionPercentageDifference: -12.0,
				Data: []DistrictConsumptionData{
					{
						Consumption:     1000,
						Period:          "2022-03-01T00:00:00+08:00",
						DistrictAverage: 17.89,
						Efficient:       8.4,
					},
					{
						Consumption:     1000,
						Period:          "2022-02-01T00:00:00+08:00",
						DistrictAverage: 17.89,
						Efficient:       8.4,
					},
				},
			},
		}

		if districtID == "D23" {
			result.Water.ConsumptionPercentageDifference = 0
		}

		return result
	default:
		result := DistrictElecConsumptionResponse{
			Elec: DistrictConsumption{
				Unit:                            greengoals.MWhUnitOfMeasurement,
				Month:                           "May 2022",
				ConsumptionPercentageDifference: -12.0,
				Data: []DistrictConsumptionData{
					{
						Consumption:     1000,
						Period:          "2022-03-01T00:00:00+08:00",
						DistrictAverage: 17.89,
						Efficient:       8.4,
					},
					{
						Consumption:     1000,
						Period:          "2022-02-01T00:00:00+08:00",
						DistrictAverage: 17.89,
						Efficient:       8.4,
					},
				},
			},
		}

		if districtID == "D23" {
			result.Elec.ConsumptionPercentageDifference = 0
		}

		return result
	}
}

