// InvalidateCachedDetails handles requests to invalidate cache
func InvalidateCachedDetails(w http.ResponseWriter, r *http.Request) error {
	// Get JWT details from request
	jwtClaims := authc.JWTFromRequest(r)

	// Remove bp details from cache
	removeCache(jwtClaims.Sub)

	w.WriteHeader(http.StatusOK)
	return nil
}

// InvalidateCacheDetailsByIamID invalidates the cache for the give IamID
func InvalidateCacheDetailsByIamID(iamID string) error {
	return removeCache(iamID)
}

// RemoveCachedDetails handles requests to remove cached details for the provided keys in the request
func RemoveCachedDetails(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	logger := loglib.GetLogger(ctx)

	var req RemoveCachedDetailsRequest
	if _, err := web.ParseAndLogJSONBody(logger, &req, r.Body); err != nil {
		return web.WithStack(err)
	}

	for _, it := range req.IamIDs {
		if err := removeCache(it); err != nil {
			return web.WithStack(err)
		}
	}
	return nil
}

