//GetBPDetails returns BPDetails from bi frost
func GetBPDetails(w http.ResponseWriter, r *http.Request) error {
	iamID := r.URL.Query().Get("iam_id")
	if iamID == "" {
		return errIamID
	}

	jwtClaims := authc.JWTClaims{
		Sub: iamID,
	}
	details, err := LoadDetails(r.Context(), jwtClaims, true)
	if err != nil {
		return err
	}
	web.RespondJSON(r.Context(), w, details, nil)
	return nil
