// enrolNotifications updates SAP (via PO) that the following accounts will subscribe to notifications jobs
func enrolNotifications(ctx context.Context, ebsAccounts []ebs.CustomerDetailsBpItem, msslAccounts []ebs.CustomerDetailsBpItem) error {
	// System-to-accounts mapping
	systems := []struct {
		system string
		items  []ebs.CustomerDetailsBpItem
	}{
		{frcpo.SystemEBS, ebsAccounts},
		{frcpo.SystemMSSL, msslAccounts},
	}
	for _, s := range systems {
