package v2

import (
	"code.in.spdigital.sg/sp-digital/infinity/pkg/basiciam"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v2/finance"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v2/saptxn"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/auth0"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/handler"
	"github.com/go-chi/chi/v5"
)

// Router registers handlers to the router provided in the argument
func Router(r chi.Router) {
	// Middlewares

	// Grouped routes
	r.Group(internal)
}

// internal is the internal chi.Router.Group routes
func internal(r chi.Router) {
	// Middlewares
	// Access token middleware
	r.Use(basiciam.RequireAccessToken(auth0.JWKSKeyFunc))
	// Audience middleware
	r.Use(basiciam.RequireClaimAudience(auth0.AudM2M))

	// To-be deprecated routes
	// TODO: Deprecate once Automic job has been disabled
	r.Group(func(r chi.Router) {
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadPayment))
		r.Get("/v2/finance/report", handler.Wrap(finance.GenerateReport)) // Finance report (via Automic for EBS)
	})
	r.Group(func(r chi.Router) {
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MUpdatePayment))
		r.Post("/v2/ebs/transactions/ack", handler.Wrap(saptxn.AcknowledgeEBS))   // Transactions acknowledgement (via Automic from EBS)
		r.Post("/v2/mssl/transactions/ack", handler.Wrap(saptxn.AcknowledgeMSSL)) // Transactions acknowledgement (via Automic for MSSL)
	})
}

