import (
	"net/http"

	"code.in.spdigital.sg/sp-digital/golang/db"
	"code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/service/greengoals"
)

// DistrictsStatic handles retrieve districts
func DistrictsStatic(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	var result []greengoals.StaticDistrict
	err := db.Tx(ctx, db.TxFromContext(ctx), func(tx db.Transactor) error {
		var err error
		if result, err = greengoals.GetDistrictsStatic(ctx, tx); err != nil {
			return err
		}
		return nil
	}, 3)
	if err != nil {
		return web.NewError(ErrDistrictsRetrieve, err.Error())
	}

	// Prepare response
	resp := translateToDistrictResponses(result)

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

// InvalidateGreenGoalsCache handles request to invalidate cache
func InvalidateGreenGoalsCache(w http.ResponseWriter, r *http.Request) error {
	// Get key details from request
	businessPartnerDetails := bp.DetailsFromRequest(r)
	if businessPartnerDetails == nil {
		return web.WithStack(ErrAccountNotLinked)
	}
	// Clear cache targets
	iamID := businessPartnerDetails.JWT.Sub
	if iamID == "" {
		errIamID := &web.Error{
			Status: http.StatusInternalServerError,
			Code:   "internal_error",
			Desc:   web.GenericErrorMessage,
			Err:    nil,
		}
		return errIamID
	}
	// Inputting the iamIDs
	iamIDs := r.URL.Query()["iam_ids"]

	ctx := r.Context()
	var clearCacheForIamIDs []string
	if len(iamIDs) > 0 {
		clearCacheForIamIDs = iamIDs
	} else {
		clearCacheForIamIDs = append(clearCacheForIamIDs, iamID)
	}

	for _, iamID := range clearCacheForIamIDs {
		greengoals.ClearGreenGoalsCache(ctx, iamID)
	}

	web.RespondJSON(ctx, w, web.Success{Message: "OK"}, nil)

	return nil
}

// DistrictsDynamic handles retrieve districts
func DistrictsDynamic(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	// Extract bp details
	bpDetails := bp.DetailsFromRequest(r)
	if bpDetails == nil {
		return web.WithStack(ErrAccountNotLinked)
	}

	iamID := bpDetails.JWT.Sub
	premises := bpDetails.Premises
	var result []greengoals.DynamicDistrict
	err := db.Tx(ctx, db.TxFromContext(ctx), func(tx db.Transactor) error {
		var err error
		if result, err = greengoals.GetDistrictsDynamic(ctx, tx, iamID, premises); err != nil {
			return err
		}
		return nil
	}, 3)
	if err != nil {
		return web.NewError(ErrDistrictsRetrieve, err.Error())
	}

	// Prepare response
	resp := translateToDynamicDistrictResponses(result)

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

func translateToDynamicDistrictResponses(dynamicDistricts []greengoals.DynamicDistrict) DynamicDistrictResponse {
	dynamicDistrictResponse := DynamicDistrictResponse{}
	for _, dynamicDistrict := range dynamicDistricts {
		dynamicDistrictResponse.Districts = append(dynamicDistrictResponse.Districts, DynamicDistrictsResponseData{
			ID:         dynamicDistrict.ID,
			Premises:   dynamicDistrict.Premises,
			Localities: dynamicDistrict.Localities,
		})
	}

	return dynamicDistrictResponse
}

func translateToDistrictResponses(districts []greengoals.StaticDistrict) StaticDistrictResponse {
	districtResponse := StaticDistrictResponse{}
	for _, district := range districts {
		districtResponse.Districts = append(districtResponse.Districts, StaticDistrictsResponseData{
			ID:         district.ID,
			Localities: district.Localities,
		})
	}

	return districtResponse
}

