package ami

import (
	"net/http"
	"sort"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/timeutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/utilities"
)

const (
	// ResponseGroupedByYear is a constant for grouping history data by year on a monthly basis
	ResponseGroupedByYear = "year"
	// ResponseGroupedByMonth is a constant for grouping history data by month in daily data points (MM/01 to MM/30 or 31)
	ResponseGroupedByMonth = "month"
	// ResponseGroupedByDay is a constant for grouping history data by day in hourly data points (00:00 to 23:00)
	ResponseGroupedByDay = "day"
	// ResponseGroupedByWeek is a constant for grouping history data by week in daily data points (Monday to Sunday)
	ResponseGroupedByWeek = "week"
)

// Charts returns series data for a given period
// Note: Only supports elec
func Charts(w http.ResponseWriter, r *http.Request) error {
	var result ChartsResponse
	ctx := r.Context()
	logger := loglib.GetLogger(ctx)

	// Parse request body
	req := ChartsRequest{}
	if _, werr := web.ParseAndLogJSONBody(logger, &req, r.Body); werr != nil {
		return web.WithStack(werr)
	}

	// Format and validate request
	if err := req.Format(); err != nil {
		return web.WithStack(err)
	}

	// Get premise payload
	bpDetails := bp.DetailsFromRequest(r)
	p, err := bpDetails.HasPremises(req.PremiseID)
	if err != nil {
		return web.WithStack(err)
	}

	// Look up energy unit
	// Note: Only supports elec
	result.Unit = utilities.UnitElectric

	// Parse and validate start date
	start, err := timeutil.ParseDatetimeOrTime(req.Start)
	if err != nil {
		return web.WithStack(ErrFromInvalid)
	}
	// Parse and validate end date
	end, err := timeutil.ParseDatetimeOrTime(req.End)
	if err != nil {
		return web.WithStack(ErrToInvalid)
	}

	var interval time.Duration
	switch req.GroupedBy {
	case ResponseGroupedByMonth:
		interval = 24 * time.Hour
	case ResponseGroupedByDay:
		interval = 30 * time.Minute
	case ResponseGroupedByWeek:
		interval = 24 * time.Hour
	}
	result.GroupedBy = req.GroupedBy

	// Interim solution
	// TODO: Remove once CR156b is in place and EMDS supports settled data
	//
	// Context:
	// EMA has requested for SRLP mechanical data (with TLF) to be shown on AMI charts
	// as an interim solution.
	//
	// To-be:
	// Once CR156b has launched, EMDS will be able to show SRLP data (without TLF),
	// and we will be moving towards that approach.
	isSRLPMech, err := hasSRLPMechMeter(ctx, p)
	if err != nil {
		return web.WithStack(err)
	}

	var groupedData ResponseGroupMap
	var min, max time.Time
	switch {
	case isSRLPMech:
		// Retrieve from BDL
		var err error
		groupedData, min, max, err = retrieveBDL(ctx, p.ContestableDetails.AccountNumber, start, end, req.GroupedBy)
		if err != nil {
			return web.NewError(ErrRetrieveBDL, err.Error())
		}

	default:
		// Retrieve from EMDS
		var err error

		// Get account numbers for EMDS query
		accountNos := GetEMDSAccountNumbers(p)
		if len(accountNos) <= 0 {
			return web.WithStack(ErrNoActiveAccounts)
		}

		// AMI meter series data
		groupedData, err = retrieveEMDS(ctx, accountNos, start, end, req.GroupedBy)
		if err != nil {
			return web.NewError(ErrRetrieveEMDS, err.Error())
		}

		// Get min and max reading date
		min, max, err = retrieveEMDSMinMax(ctx, accountNos, interval, req.GroupedBy)
		if err != nil {
			return web.NewError(ErrRetrieveMinMax, err.Error())
		}
	}

	// Fill data series gaps
	groupedData = FillSeriesGaps(start, end, req.GroupedBy, interval, groupedData)
	// Convert AMI meter series data to response
	result.History = ToHistoryTypes(min, max, req.GroupedBy, interval, groupedData)

	web.RespondJSON(ctx, w, result, nil)
	return nil
}

// FillSeriesGaps fill data point/series gaps for the provided data response group
func FillSeriesGaps(start, end time.Time, groupedBy string, interval time.Duration, data ResponseGroupMap) ResponseGroupMap {
	// Set start/end date based on calendar month/day
	// Prepare date range for data series filling
	var groupKey func(time.Time) string
	var dataPointKey func(time.Time) string
	switch groupedBy {
	case ResponseGroupedByYear:
		// Set start date to first day of the start date's year
		start = timeutil.Date(start.Year(), 1, 1, 0, 0)
		// Set end date to last day of the end date's year
		end = timeutil.Date(end.Year(), 1, 1, 0, 0)
		end = end.AddDate(1, 0, -1)

		groupKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), 1, 1, 0, 0).Format(time.RFC3339)
		}
		dataPointKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), ts.Month(), 1, 0, 0).Format(time.RFC3339)
		}
	case ResponseGroupedByMonth:
		// Set start date to first day of the start date's month
		start = timeutil.Date(start.Year(), start.Month(), 1, 0, 0)
		// Set end date to last day of the end date's month
		end = timeutil.Date(end.Year(), end.Month(), 1, 0, 0)
		end = end.AddDate(0, 1, -1)

		groupKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), ts.Month(), 1, 0, 0).Format(time.RFC3339)
		}
		dataPointKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), ts.Month(), ts.Day(), 0, 0).Format(time.RFC3339)
		}
	case ResponseGroupedByDay:
		// Set start date as 00:00
		start = timeutil.Date(start.Year(), start.Month(), start.Day(), 0, 0)
		// Set end date as 23:30
		end = timeutil.Date(end.Year(), end.Month(), end.Day(), 23, 30)

		groupKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), ts.Month(), ts.Day(), 0, 0).Format(time.RFC3339)
		}
		dataPointKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), ts.Month(), ts.Day(), ts.Hour(), ts.Minute()).Format(time.RFC3339)
		}
	case ResponseGroupedByWeek:
		// Set start date as 00:00
		start = timeutil.Date(start.Year(), start.Month(), start.Day(), 0, 0)
		// Set end date as 23:59
		end = timeutil.Date(end.Year(), end.Month(), end.Day(), 23, 59)
		dataPointKey = func(ts time.Time) string {
			return timeutil.Date(ts.Year(), ts.Month(), ts.Day(), ts.Hour(), ts.Minute()).Format(time.RFC3339)
		}
	default:
		return data
	}

	// Fill data series
	for ts := start; !ts.After(end); ts = ts.Add(interval) {
		var group3339 string
		if groupedBy == ResponseGroupedByWeek {
			group3339 = start.Format(time.RFC3339)
		} else {
			group3339 = groupKey(ts)
		}

		items, ok := data[group3339]
		if !ok {
			items = DataPointGroupMap{}
		}

		dataPoint3339 := dataPointKey(ts)
		item, ok := items[dataPoint3339]
		if !ok {
			item = DataType{Date: dataPoint3339, Consumption: 0.0}
		}
		item.Consumption = formatKWH(item.Consumption)

		items[dataPoint3339] = item
		data[group3339] = items
	}

	return data
}

// ToHistoryTypes converts the provided data response group to HistoryType response
func ToHistoryTypes(min, max time.Time, groupedBy string, interval time.Duration, data ResponseGroupMap) []HistoryType {
	result := []HistoryType{}

	var calculateEnd func(time.Time) time.Time
	switch groupedBy {
	case ResponseGroupedByYear:
		calculateEnd = func(ts time.Time) time.Time {
			return ts.AddDate(1, 0, 0).Add(-interval)
		}
	case ResponseGroupedByMonth:
		calculateEnd = func(ts time.Time) time.Time {
			return ts.AddDate(0, 1, 0).Add(-interval)
		}
	case ResponseGroupedByDay:
		calculateEnd = func(ts time.Time) time.Time {
			return ts.AddDate(0, 0, 1).Add(-interval)
		}
	case ResponseGroupedByWeek:
		calculateEnd = func(ts time.Time) time.Time {
			return ts.AddDate(0, 0, 7).Add(-interval)
		}
	}

	for gk, gv := range data {
		start, err := time.Parse(time.RFC3339, gk)
		if err != nil {
			continue // Skip invalid date
		}
		end := calculateEnd(start)
		// Create history type
		h := HistoryType{
			Start:    start.Format(time.RFC3339),
			End:      end.Format(time.RFC3339),
			Next:     !max.IsZero() && max.After(end),
			Previous: !min.IsZero() && min.Before(start),
			Data:     []DataType{},
		}

		// Append data types to history type
		for _, dv := range gv {
			h.Data = append(h.Data, dv)
		}
		// Sort data types (data points)
		h.Data = sortDataType(h.Data)
		// Append to history types
		result = append(result, h)
	}
	// Sort history types (groups)
	result = sortHistoryType(result)

	return result
}

// Format formats and validates the request fields
func (c *ChartsRequest) Format() error {
	if c.PremiseID == "" {
		return ErrPremiseIDEmpty
	}

	switch c.GroupedBy {
	case ResponseGroupedByDay:
	case ResponseGroupedByMonth:
	case ResponseGroupedByWeek:
	default:
		return ErrGroupedByInvalid
	}
	return nil
}

// sortDataType sorts DataType by Date (RFC3339)
func sortDataType(slice []DataType) []DataType {
	sort.SliceStable(slice, func(i, j int) bool {
		si, err := time.Parse(time.RFC3339, slice[i].Date)
		if err != nil {
			return false
		}
		sj, err := time.Parse(time.RFC3339, slice[j].Date)
		if err != nil {
			return true
		}
		return si.Before(sj)
	})
	return slice
}

// sortHistoryType sorts DataType by Start (RFC3339)
func sortHistoryType(slice []HistoryType) []HistoryType {
	sort.SliceStable(slice, func(i, j int) bool {
		si, err := time.Parse(time.RFC3339, slice[i].Start)
		if err != nil {
			return false
		}
		sj, err := time.Parse(time.RFC3339, slice[j].Start)
		if err != nil {
			return true
		}
		return si.After(sj)
	})
	return slice
}

