package usage

import (
	"context"
	"sort"

	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/numutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/service/consumption"
	"golang.org/x/sync/errgroup"
)

// AsyncRetrieveBilledUsage retrieves a premises's billed usage data
func AsyncRetrieveBilledUsage(ctx context.Context, g *errgroup.Group, p bp.PremisesType) chan ChartsResponse {
	out := make(chan ChartsResponse, 1)

	g.Go(func() error {
		defer close(out)

		data, err := consumption.RetrieveBilled(ctx, p)
		if err != nil {
			return err
		}

		// Construct ChartsResponse
		result := ChartsResponse{
			Elec: ChartData{
				Data: []DataType{},
			},
			Gas: ChartData{
				Data: []DataType{},
			},
			Water: ChartData{
				Data: []DataType{},
			},
		}
		for _, it := range data.Elec {
			result.Elec.Data = append(result.Elec.Data, newDataType(it))
		}
		for _, it := range data.Gas {
			result.Gas.Data = append(result.Gas.Data, newDataType(it))
		}
		for _, it := range data.Water {
			result.Water.Data = append(result.Water.Data, newDataType(it))
		}
		// Calculate averages
		result.Elec.calculateAverage()
		result.Gas.calculateAverage()
		result.Water.calculateAverage()
		// Sort by period
		result.Elec.sort()
		result.Gas.sort()
		result.Water.sort()

		out <- result
		return nil
	})

	return out
}

// calculateAverage calcuates the average consumption of the data points
func (c *ChartData) calculateAverage() {
	var total float64
	count := len(c.Data)
	for _, it := range c.Data {
		total += it.Consumption.Previous
		total += it.Consumption.Current
	}
	if total <= 0 || count <= 0 {
		c.AverageConsumption = 0
	} else {
		c.AverageConsumption = numutil.TruncateFloat(total/float64(count), 2)
	}
}

// sort sorts the data points by period in descending order
func (c *ChartData) sort() {
	sort.SliceStable(c.Data, func(i, j int) bool {
		return c.Data[i].Period.After(c.Data[j].Period) // descending order
	})
}

// newDataType creates a new DataType from consumption.DataPoint
func newDataType(it consumption.DataPoint) DataType {
	return DataType{
		Period: it.Period,
		Status: it.Status,
		Unit:   it.Unit,
		Consumption: ConsumptionType{
			Previous: it.Consumption.Previous,
			Current:  it.Consumption.Current,
		},
	}
}

package greengoals

import (
	"net/http"
	"os"

	"code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/service/greengoals"
)

const (
	version = "v4"
)

func TargetsDynamic(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	// Extract bp details
	bpDetails := bp.DetailsFromRequest(r)
	if bpDetails == nil {
		return web.WithStack(ErrAccountNotLinked)
	}

	iamID := bpDetails.JWT.Sub
	premises := bpDetails.Premises
	results, err := greengoals.GetTargetsDynamic(ctx, iamID, version, premises)
	if err != nil {
		return web.NewError(ErrGoalsRetrieve, err.Error())
	}

	// Prepare response
	resp := translateToDynamicTargetsResponses(results)

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

func translateToDynamicTargetsResponses(goals []greengoals.Goal) DynamicTargetsResponse {
	targetsResponse := DynamicTargetsResponse{}
	if len(goals) >= 1 {
		goal := goals[0]
		var premises []Premise
		for _, premise := range goal.Premises {
			premises = append(premises, Premise{
				ID: premise.ID,
				Data: Data{
					Used:   premise.Data.Used,
					Target: premise.Data.Target,
				},
				ConsumptionPercentageDifference: premise.ConsumptionPercentageDifference,
				CostDifferenceInCents:           premise.CostDifferenceInCents,
			})
		}

		targetsResponse.Goals = append(targetsResponse.Goals, Goal{
			ID:       goal.ID,
			Unit:     goal.Unit,
			Month:    goal.Month,
			Premises: premises,
		})
	}

	return targetsResponse
}

func isExistedGreenGoalsStaticResponseEnabled() bool {
	return os.Getenv("GREEN_GOALS_ENABLE_STATIC_RESPONSE") == "1"
}

func TargetsStatic(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	results, err := greengoals.GetStaticGoals(ctx, version)
	if err != nil {
		return web.NewError(ErrGoalsRetrieve, err.Error())
	}

	// Prepare response
	resp := translateStaticTargetsResponses(results)

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

func translateStaticTargetsResponses(staticGoals []greengoals.StaticGoal) StaticTargetsResponse {
	targetsResponse := StaticTargetsResponse{}
	if len(staticGoals) >= 1 {
		goal := staticGoals[0]
		var staticData []StaticData
		for _, data := range goal.Overall.Progressive.Data {
			staticData = append(staticData, StaticData{
				Year:  data.Year,
				Value: data.Value,
			})
		}

		targetsResponse.Goals = append(targetsResponse.Goals, StaticGoal{
			ID:          goal.ID,
			Title:       goal.Title,
			Description: goal.Description,
			Overall: Overall{
				SavedPercentage: goal.Overall.SavedPercentage,
				Progressive: Progressive{
					Unit: goal.Overall.Progressive.Unit,
					Data: staticData,
				},
			},
		})
	}

	return targetsResponse
}

