func TestRetrieveEMDSMinMax(t *testing.T) {
	testCases := []struct {
		groupedBy   string
		expectedMin time.Time
		expectedMax time.Time
	}{
		{ResponseGroupedByDay, timeutil.Date(2018, 5, 15, 0, 0), timeutil.Date(2018, 5, 30, 23, 30)},
		{ResponseGroupedByMonth, timeutil.Date(2018, 5, 1, 0, 0), timeutil.Date(2018, 9, 30, 0, 0)},
	}

	for _, tc := range testCases {
		t.Run(tc.groupedBy, func(t *testing.T) {
			// Given:
			ctx := context.Background()
			given := []string{"ACC1", "ACC2"}

			// Mocks:
			var interval time.Duration
			switch tc.groupedBy {
			case ResponseGroupedByDay:
				interval = 30 * time.Minute
				ctx = emds.MockAMIMinMaxByDay(ctx, nil, emds.AMIMinMaxByDayResponse{
					MinAvailableDate: "2018-05-15",
					MaxAvailableDate: "2018-05-30",
				}, nil)
			case ResponseGroupedByMonth:
				interval = 24 * time.Hour
				ctx = emds.MockAMIMinMaxByMonth(ctx, nil, emds.AMIMinMaxByMonthResponse{
					MinAvailableMonth: "2018-05",
					MaxAvailableMonth: "2018-09",
				}, nil)
			}

			// When:
			min, max, err := retrieveEMDSMinMax(ctx, given, interval, tc.groupedBy)

			// Then:
			assert.NoError(t, err)
			assert.Equal(t, tc.expectedMin, min)
			assert.Equal(t, tc.expectedMax, max)
		})
	}
}

