import (
	"context"
	"strings"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/timeutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/emds"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
)

// Internal data structure used to aggregate/lookup grouped data for multiple accounts
type (
	// ResponseGroupMap represents response groups in map data structure (i.e. by calendar month, by logical day)
	ResponseGroupMap map[string]DataPointGroupMap
	// DataPointGroupMap represents data point groups in map data structure (i.e. by timestamp intervals)
	DataPointGroupMap map[string]DataType
)

const (
	hhmmKeyPrefix = "t_"
	ddKeyPrefix   = "day_"
)

// GetEMDSAccountNumbers returns account numbers associated to this premise for EMDS query
// | Contestable type | Source | Explanation                                             |
// |:----------------:|:------:|:-------------------------------------------------------:|
// | Non-contestable  | EBS    | No MSSL account                                         |
// | IOBR and BOBR-C  | MSSL   | Readings are "supposed" to be mapped to EBS only.       |
// |                  |        | As of 20181229, seeing data on MSSL as well. But we'll  |
// |                  |        | just stick to EBS since that should be the expected     |
// |                  |        | behaviour.                                              |
// |                  |        | (Update) As of 20190109, we've confirmed that IOBR is   |
// |                  |        | not on EBS :/, hence switching to use MSSL account for  |
// |                  |        | both.				                                           |
// | Retailer         | MSSL   | Readings are mapped to both EBS and MSSL, even though   |
// |                  |        | we're expecting it to be only on MSSL. Use MSSL so that |
// |                  |        | includes SP Pool readings and since xOBR has readings   |
// |                  |        | on MSSL, those will be included as well.                |
// | SP Pool          | MSSL   | Readings are mapped to MSSL only                        |
func GetEMDSAccountNumbers(p bp.PremisesType) []string {
	accountNos := []string{}
	switch p.ContestableDetails.ContestableType {
	// EBS account number
	case "": // Non-contestable
		a, ok := p.GetActiveEBSAccount()
		if ok {
			accountNos = append(accountNos, a.AccountNumber)
		}

		// MSSL account number
	case frcpo.ContestableTypeSP,
		frcpo.ContestableTypeRetailer,
		frcpo.ContestableTypeIOBR,
		frcpo.ContestableTypeBOBRC:

		if contestableAccNo := p.ContestableDetails.AccountNumber; contestableAccNo != "" {
			accountNos = append(accountNos, contestableAccNo)
		}
	}

	return accountNos
}

func retrieveEMDSMinMax(ctx context.Context, accountNos []string, interval time.Duration, responseGroupedBy string) (time.Time, time.Time, error) {
	var min, max time.Time
	switch responseGroupedBy {
	case ResponseGroupedByDay:
		resp, err := emds.AMIMinMaxByDay(ctx, emds.AMIMinMaxByDayRequest{
			AccountNumbers: accountNos,
		})
		if err != nil {
			return time.Time{}, time.Time{}, err
		}
		if resp.MinAvailableDate != "" {
			min, err = time.ParseInLocation("2006-01-02", resp.MinAvailableDate, timeutil.SGT)
			if err != nil {
				return time.Time{}, time.Time{}, err
			}
		}
		if resp.MaxAvailableDate != "" {
			max, err = time.ParseInLocation("2006-01-02", resp.MaxAvailableDate, timeutil.SGT)
			if err != nil {
				return time.Time{}, time.Time{}, err
			}
			// Set max to last interval of the day
			max = max.AddDate(0, 0, 1).Add(-interval)
		}
	case ResponseGroupedByMonth:
		resp, err := emds.AMIMinMaxByMonth(ctx, emds.AMIMinMaxByMonthRequest{
			AccountNumbers: accountNos,
		})
		if err != nil {
			return time.Time{}, time.Time{}, err
		}
		if resp.MinAvailableMonth != "" {
			min, err = time.ParseInLocation("2006-01", resp.MinAvailableMonth, timeutil.SGT)
			if err != nil {
				return time.Time{}, time.Time{}, err
			}
		}
		if resp.MaxAvailableMonth != "" {
			max, err = time.ParseInLocation("2006-01", resp.MaxAvailableMonth, timeutil.SGT)
			if err != nil {
				return time.Time{}, time.Time{}, err
			}
			// Set max to last day of the calendar month
			max = max.AddDate(0, 1, 0).Add(-interval)
		}
	case ResponseGroupedByWeek:
		resp, err := emds.AMIMinMaxByDay(ctx, emds.AMIMinMaxByDayRequest{
			AccountNumbers: accountNos,
		})
		if err != nil {
			return time.Time{}, time.Time{}, err
		}
		if resp.MinAvailableDate != "" {
			min, err = time.ParseInLocation("2006-01-02", resp.MinAvailableDate, timeutil.SGT)
			if err != nil {
				return time.Time{}, time.Time{}, err
			}
		}
		if resp.MaxAvailableDate != "" {
			max, err = time.ParseInLocation("2006-01-02", resp.MaxAvailableDate, timeutil.SGT)
			if err != nil {
				return time.Time{}, time.Time{}, err
			}
			// Set max to last interval of the week
			max = max.AddDate(0, 0, 7).Add(-interval)
		}
	}

	return min, max, nil
}

// retrieveEMDS retrieves AMI intervals from EMDS (Data team)
func retrieveEMDS(ctx context.Context, accountNos []string, start, end time.Time, responseGroupedBy string) (ResponseGroupMap, error) {
	switch responseGroupedBy {
	case ResponseGroupedByDay:
		dateLayout := "2006-01-02"
		resp, err := emds.AMIHalfHourlyByDay(ctx, emds.AMIHalfHourlyByDayRequest{
			AccountNumbers: accountNos,
			StartDate:      start.In(timeutil.SGT).Format(dateLayout),
			EndDate:        end.In(timeutil.SGT).Format(dateLayout),
		})
		if err != nil {
			return nil, err
		}
		return aggregateHalfHourlyReadings(ctx, resp.AccountsList), nil
	case ResponseGroupedByMonth:
		dateLayout := "2006-01"
		resp, err := emds.AMIDailyByMonth(ctx, emds.AMIDailyByMonthRequest{
			AccountNumbers: accountNos,
			StartMonth:     start.In(timeutil.SGT).Format(dateLayout),
			EndMonth:       end.In(timeutil.SGT).Format(dateLayout),
		})
		if err != nil {
			return nil, err
		}
		return aggregateDailyReadings(ctx, resp.AccountsList), nil
	case ResponseGroupedByWeek:
		dateLayout := "2006-01-02"
		resp, err := emds.AMIHalfHourlyByDay(ctx, emds.AMIHalfHourlyByDayRequest{
			AccountNumbers: accountNos,
			StartDate:      start.In(timeutil.SGT).Format(dateLayout), // weekStartDate
			EndDate:        end.In(timeutil.SGT).Format(dateLayout),   // weekEndDate
		})
		if err != nil {
			return nil, err
		}
		return aggregateWeeklyReadings(ctx, resp.AccountsList, start), nil
	}
	return nil, ErrGroupedByInvalid
}

// aggregateHalfHourlyReadings combines the consumption data for the list of accounts provided while retaining the grouped by structure
func aggregateHalfHourlyReadings(ctx context.Context, accs []emds.AMIHalfHourlyByDayAccountsList) ResponseGroupMap {
	logger := loglib.GetLogger(ctx)
	result := ResponseGroupMap{}
	for _, acc := range accs {
		// Iterate through all the groups (by day)
		for _, it := range acc.HalfHourlyByDayDetails {
			// Get group date
			groupedByDate, err := time.ParseInLocation("2006-01-02", it.Date, timeutil.SGT)
			if err != nil {
				logger.Errorf("[error] Invalid EMDS half-hourly group by day date: %v", err)
				continue
			}
			// Find if group exists in seen group map
			// So that we can aggregate/update the group information
			groupedByDateStr := groupedByDate.Format(time.RFC3339)
			groupedBy, ok := result[groupedByDateStr]
			if !ok {
				groupedBy = map[string]DataType{}
			}

			// Iterate through all the data points (half-hourly)
			for k, v := range it.HalfHourlyReadings {
				hhmm := strings.Replace(k, hhmmKeyPrefix, "", 1)
				dataPointDate, err := time.ParseInLocation("2006-01-021504", it.Date+hhmm, timeutil.SGT)
				if err != nil {
					logger.Errorf("[error] Invalid EMDS half-hourly data point date: %v", err)
					continue
				}

				dataPointDateStr := dataPointDate.Format(time.RFC3339)
				dataPoint, ok := groupedBy[dataPointDateStr]
				if !ok {
					dataPoint = DataType{
						Date: dataPointDateStr,
					}
				}
				dataPoint.Consumption += v.MeterReading
				groupedBy[dataPointDateStr] = dataPoint
			}
			result[groupedByDateStr] = groupedBy
		}
	}
	return result
}

// aggregateDailyReadings combines the consumption data for the list of accounts provided while retaining the grouped by structure
func aggregateDailyReadings(ctx context.Context, accs []emds.AMIDailyByMonthAccountsList) ResponseGroupMap {
	logger := loglib.GetLogger(ctx)
	result := ResponseGroupMap{}
	for _, acc := range accs {
		// Iterate through all the groups (by day)
		for _, it := range acc.DailyByMonthDetails {
			// Get group date
			groupedByDate, err := time.ParseInLocation("2006-01", it.Month, timeutil.SGT)
			if err != nil {
				logger.Errorf("[error] Invalid EMDS daily group by month date: %v", err)
				continue
			}
			// Find if group exists in seen group map
			// So that we can aggregate/update the group information
			groupedByDateStr := groupedByDate.Format(time.RFC3339)
			groupedBy, ok := result[groupedByDateStr]
			if !ok {
				groupedBy = map[string]DataType{}
			}

			// Iterate through all the data points (daily)
			for k, v := range it.DailyReadings {
				dd := strings.Replace(k, ddKeyPrefix, "", 1)
				dataPointDate, err := time.ParseInLocation("2006-0102", it.Month+dd, timeutil.SGT)
				if err != nil {
					logger.Errorf("[error] Invalid EMDS daily data point date: %v", err)
					continue
				}

				dataPointDateStr := dataPointDate.Format(time.RFC3339)
				dataPoint, ok := groupedBy[dataPointDateStr]
				if !ok {
					dataPoint = DataType{
						Date: dataPointDateStr,
					}
				}
				dataPoint.Consumption += v
				groupedBy[dataPointDateStr] = dataPoint
			}
			result[groupedByDateStr] = groupedBy
		}
	}
	return result
}

// aggregateWeeklyReadings combines the weekly consumption data for the list of accounts provided while retaining the grouped by structure
func aggregateWeeklyReadings(ctx context.Context, accs []emds.AMIHalfHourlyByDayAccountsList, weekStartDate time.Time) ResponseGroupMap {
	logger := loglib.GetLogger(ctx)
	result := ResponseGroupMap{}
	dataPoint := map[string]DataType{}
	for _, acc := range accs {
		// Iterate through all the groups (by day)
		for _, it := range acc.HalfHourlyByDayDetails {
			// Parse data point date
			dataTypeDate, err := time.ParseInLocation("2006-01-02", it.Date, timeutil.SGT)
			if err != nil {
				logger.Errorf("[aggregateWeeklyReadings] Invalid EMDS weekly group by day date: %v", err)
				continue
			}

			// init data type
			dataTypeDateStr := dataTypeDate.Format(time.RFC3339)
			dataType, ok := dataPoint[dataTypeDateStr]
			if !ok {
				dataType = DataType{
					Date: dataTypeDateStr,
				}
			}
			dataType.Consumption += it.DailySumValue
			// Set data point into group (weekly)
			dataPoint[dataTypeDateStr] = dataType
		}
	}

	// set data point map into response map
	result[weekStartDate.Format(time.RFC3339)] = dataPoint
	return result
}

