func TestHasPremises(t *testing.T) {
	t.Parallel()
	// Given:
	given := "premiseid"
	details := &Details{
		Premises: []PremisesType{
			{ID: given, ContestableDetails: ContestableDetailsType{ContestableType: "something"}},
		},
	}

	// When:
	result, err := details.HasPremises(given)

	// Then:
	require.NoError(t, err)
	require.Equal(t, given, result.ID)
	require.Equal(t, "something", result.ContestableDetails.ContestableType)
}

func TestHasPremises_Error(t *testing.T) {
	t.Parallel()
	// Given:
	given := "premiseid"
	details := &Details{
		Premises: []PremisesType{
			{ID: "irrelevantpremiseid", ContestableDetails: ContestableDetailsType{ContestableType: "something"}},
		},
	}

	// When:
	result, err := details.HasPremises(given)

	// Then:
	require.Equal(t, ErrPremiseUnauthorized, err)
	require.EqualValues(t, PremisesType{}, result)
}

