type contextKey string

const (
	detailsContextKey = contextKey("bp_details")
)

// DetailsFromRequest returns bp details inside the request context
func DetailsFromRequest(r *http.Request) *Details {
	return DetailsFromContext(r.Context())
}

// DetailsFromContext returns bp.Details inside the context
func DetailsFromContext(ctx context.Context) *Details {
	value, ok := ctx.Value(detailsContextKey).(*Details)
	if ok {
		return value
	}
	return nil
}

// LoadDetailsToContext loads the BP details and sets into context
func LoadDetailsToContext(ctx context.Context, jwtClaims authc.JWTClaims) (context.Context, error) {
	// Returns cached bp details or loads new bp details into the cache if not present
	d, err := LoadDetails(ctx, jwtClaims, true)
	if err != nil {
		return ctx, web.WithStack(err)
	}

	// Set details into context
	return setDetailsContext(ctx, &d), nil
}

func setDetailsContext(ctx context.Context, details *Details) context.Context {
	return context.WithValue(ctx, interface{}(detailsContextKey), details)
}

// =====================
// FOR USE IN TESTS ONLY
// =====================

// ProvidesDetails puts account details into the request context
// This is ONLY meant for tests.
func ProvidesDetails(details Details, r *http.Request) *http.Request {
	ctx := ProvidesDetailsToContext(details, r.Context())
	return r.WithContext(ctx)
}

// ProvidesDetailsToContext puts account details into the context
// This is ONLY meant for tests.
func ProvidesDetailsToContext(details Details, ctx context.Context) context.Context {
	if os.Getenv("APPENV") != "test" {
		panic("NOT for use in APPENV=" + os.Getenv("APPENV"))
	}
	return setDetailsContext(ctx, &details)
}

