func TestAppendShared(t *testing.T) {
	// Given:
	premises := []PremisesType{
		{ID: "OWNED", SharedResourceDetails: SharedResourceDetailsType{ID: "", Owner: true, OwnerIamID: "OWNER"}},
		{ID: "SHARED1", SharedResourceDetails: SharedResourceDetailsType{ID: "", Owner: false, OwnerIamID: "SHARED1"}},
		{ID: "NOLONGERSHARED", SharedResourceDetails: SharedResourceDetailsType{ID: "", Owner: false, OwnerIamID: "NOLONGERSHARED"}},
	}

	// Expected:
	expectedSharedID := "SHARED2"
	expected := []PremisesType{
		{
			ID: "OWNED",
			SharedResourceDetails: SharedResourceDetailsType{
				ID:               "rid://jarvis/premises?iam_id=OWNER&id=OWNED",
				Owner:            true,
				OwnerIamID:       "OWNER",
				OwnerName:        "Owner",
				OwnerDisplayName: "OwnerDisplayName",
				OwnerEmail:       "owner@test.com",
				MaxUsers:         5,
				Users: []SharedResourceUserType{
					{
						ID:          "3",
						IamID:       "USERIAMID",
						Name:        "User",
						DisplayName: "UserDisplayName",
						Email:       "user@test.com",
						FullAccess:  true,
					},
				},
				Invites: []SharedResourceInviteType{
					{"4", "invited@gmail.com"},
				},
			},
		},
		{
			ID: "SHARED1",
			SharedResourceDetails: SharedResourceDetailsType{
				ID:               "rid://jarvis/premises?iam_id=SHARED1&id=SHARED1",
				Owner:            false,
				OwnerIamID:       "SHARED1",
				OwnerName:        "Shared 1",
				OwnerDisplayName: "Shared 1 DisplayName",
				OwnerEmail:       "shared1@test.com",
				MaxUsers:         5,
				Users: []SharedResourceUserType{
					{
						ID:          "3",
						IamID:       "USERIAMID",
						Name:        "User",
						DisplayName: "UserDisplayName",
						Email:       "user@test.com",
						FullAccess:  true,
					},
					{
						ID:          "4",
						IamID:       "USERIAMID1",
						Name:        "User1",
						DisplayName: "UserDisplayName1",
						Email:       "user1@test.com",
						FullAccess:  false,
					},
				},
				Invites: []SharedResourceInviteType{},
			},
		},
		{
			ID:   expectedSharedID,
			Type: "Others",
			SharedResourceDetails: SharedResourceDetailsType{
				ID:               "rid://jarvis/premises?iam_id=SHARED2&id=SHARED2",
				Owner:            false,
				OwnerIamID:       expectedSharedID,
				OwnerName:        "Shared 2",
				OwnerDisplayName: "Shared 2 DisplayName",
				OwnerEmail:       "shared2@test.com",
				MaxUsers:         5,
				Users:            []SharedResourceUserType{},
				Invites: []SharedResourceInviteType{
					{"4", "invited@gmail.com"},
				},
			},
			Accounts: []AccountsType{
				{System: frcpo.SystemEBS, Utilities: []string{}, PremiseNumber: expectedSharedID},
			},
		},
	}
	cleanUpCache := func() { RemoveCache(expectedSharedID) }

	testCases := []struct {
		cached bool
	}{
		{cached: true},
		{cached: false},
	}

	for _, tc := range testCases {
		t.Run(fmt.Sprintf("cached:%t", tc.cached), func(t *testing.T) {
			// Given:
			ctx := context.Background()
			httpmock.Activate()
			defer httpmock.DeactivateAndReset()

			auth0.HttpMock()
			iamID := "OWNER"

			// Mock:

			responderDelete, err := httpmock.NewJsonResponse(http.StatusOK, profileapi.DeleteSharedResourceUserResponse{})
			require.NoError(t, err)

			u := profileapi.SharedResourcesURL

			httpmock.RegisterResponder(http.MethodPost, u, httpmock.ResponderFromMultipleResponses(
				[]*http.Response{
					testhelpers.NewFileResponse(http.StatusOK, "internal/stubs/profileapi/testdata/sharedresources/multiple.json"),
					responderDelete,
				},
			))

			ctx = profileapi.MockSharedResourcesf(ctx, "", "internal/stubs/profileapi/testdata/sharedresources/multiple.json", nil)
			// Mock delete shared resource of previously owned premises
			mockDeleteReq := profileapi.DeleteSharedResourceRequest{
				Variables: profileapi.DeleteSharedResourceVariables{
					ResourceID: "rid://jarvis/premises?iam_id=OWNER&id=PREVIOUSLY_OWNED",
				},
			}
			require.NoError(t, mockDeleteReq.Format())
			ctx = profileapi.MockDeleteSharedResource(ctx, &mockDeleteReq, profileapi.DeleteSharedResourceResponse{}, nil)
			// Remove cached since we're expecting it to be cached when load details is triggered or injected to the cached
			cleanUpCache()
			defer cleanUpCache()
			if tc.cached {
				mockSharedCachedDetails(expectedSharedID)
			} else {
				ctx = mockSharedLoadDetails(ctx, expectedSharedID)
			}

			// When:
			result, err := appendShared(ctx, premises, iamID)

			// Then:
			require.NoError(t, err)
			// Sort before assertion to conform to expected's sorting algorithm
			sort.SliceStable(result, func(i, j int) bool {
				return result[i].ID < result[j].ID
			})
			require.Equal(t, len(expected), len(result))
			for i := range result {
				require.Equal(t, expected[i].ID, result[i].ID)
				require.Equal(t, expected[i].Type, result[i].Type)
				require.Equal(t, expected[i].SharedResourceDetails, result[i].SharedResourceDetails)
			}
		})
	}
}

