func TestRetrieveBDL_Daily(t *testing.T) {
	// Given:
	ctx := context.Background()
	accNo := "BDLDAILYACCNO"
	start := timeutil.Date(2018, 1, 1, 0, 0)
	end := timeutil.Date(2019, 1, 1, 0, 0)

	// Mocks:
	expectedReq := uportalbdl.DailyRequest{
		AccNo:    accNo,
		FromDate: start.Format("2006-01-02"),
		ToDate:   end.Format("2006-01-02"),
	}
	mockedResp := uportalbdl.DailyResponse{
		ResponseData: uportalbdl.DailyResponseData{
			AvailableUntil: "2018-12-25",
			IntervalData: []uportalbdl.DailyIntervalData{
				{FrequencyUsage: "2018-03-22", CustomerReading: "0.123456789", DateField: ""},
				{FrequencyUsage: "2018-03-21", CustomerReading: "123456789.1", DateField: ""},
				{FrequencyUsage: "2018-03-20", CustomerReading: "", DateField: ""},
				{FrequencyUsage: "2018-03-19", CustomerReading: "123456789", DateField: ""},
				{FrequencyUsage: "INVALID", CustomerReading: "123456789", DateField: ""},
				{FrequencyUsage: "2018-01-31", CustomerReading: "INVALID", DateField: ""},
			},
		},
	}
	ctx = uportalbdl.MockDaily(ctx, &expectedReq, mockedResp, nil)

	// When:
	result, min, max, err := retrieveBDL(ctx, accNo, start, end, ResponseGroupedByMonth)

	// Then:
	require.NoError(t, err)
	require.Equal(t, frcLaunchDate, min)
	require.Equal(t, timeutil.Date(2018, 12, 25, 0, 0), max)
	require.Len(t, result, 2)
	marchMap := result["2018-03-01T00:00:00+08:00"]
	require.Len(t, marchMap, 4)
	require.Equal(t, DataType{"2018-03-22T00:00:00+08:00", 0.123456789}, marchMap["2018-03-22T00:00:00+08:00"])
	require.Equal(t, DataType{"2018-03-21T00:00:00+08:00", 123456789.1}, marchMap["2018-03-21T00:00:00+08:00"])
	require.Equal(t, DataType{"2018-03-20T00:00:00+08:00", 0.0}, marchMap["2018-03-20T00:00:00+08:00"])
	require.Equal(t, DataType{"2018-03-19T00:00:00+08:00", 123456789.0}, marchMap["2018-03-19T00:00:00+08:00"])
	janMap := result["2018-01-01T00:00:00+08:00"]
	require.Len(t, janMap, 1)
	require.Equal(t, DataType{"2018-01-31T00:00:00+08:00", 0.0}, janMap["2018-01-31T00:00:00+08:00"])
}

