func TestHasSRLPMechMeter(t *testing.T) {
	testCases := []struct {
		testdata string
		expected bool
	}{
		{"success_mech", false},
		{"success_ami", false},
		{"success_srlp", true},
		{"success_amisrlp", false},
		{"success_smmu", false},
		{"empty", false},
	}

	for _, tc := range testCases {
		t.Run(tc.testdata, func(t *testing.T) {
			// Given:
			ctx := context.Background()
			accNo := tc.testdata + "ACCNO"
			given := bp.PremisesType{
				Accounts: []bp.AccountsType{
					{AccountStatus: frcpo.AccountStatusActive, AccountNumber: accNo, System: frcpo.SystemEBS},
				},
			}
			// Clean-up redis
			require.NoError(t, removeSRLPMechFlagCache(accNo))

			// Mocks:
			ctx = meterinstallationdetails.Mock(ctx, "", fmt.Sprintf("internal/stubs/frcpo/ebs/meterinstallationdetails/fixtures/%s.json", tc.testdata), nil)

			// When:
			result, err := hasSRLPMechMeter(ctx, given)

			// Then:
			require.NoError(t, err)
			require.Equal(t, tc.expected, result)
		})
	}
}

func TestHasSRLPMechMeter_Cached(t *testing.T) {
	testCases := []struct {
		cachedValue bool
		expected    bool
	}{
		{true, true},
		{false, false},
	}

	for _, tc := range testCases {
		t.Run(fmt.Sprintf("%t", tc.cachedValue), func(t *testing.T) {
			// Given:
			ctx := context.Background()
			accNo := fmt.Sprintf("%tACCNO", tc.cachedValue)
			given := bp.PremisesType{
				Accounts: []bp.AccountsType{
					{AccountStatus: frcpo.AccountStatusActive, AccountNumber: accNo, System: frcpo.SystemEBS},
				},
			}
			require.NoError(t, saveSRLPMechFlagCache(accNo, tc.cachedValue))
			// Clean-up redis
			defer removeSRLPMechFlagCache(accNo)

			// When:
			result, err := hasSRLPMechMeter(ctx, given)

			// Then:
			require.NoError(t, err)
			require.Equal(t, tc.expected, result)
		})
	}
}

