var frcLaunchDate = timeutil.Date(2018, 3, 1, 0, 0)

// retrieveBDL retrieves AMI intervals from BDL microservice (UPortal microservices)
func retrieveBDL(ctx context.Context, accountNo string, start, end time.Time, responseGroupedBy string) (ResponseGroupMap, time.Time, time.Time, error) {
	result := ResponseGroupMap{}
	dateLayout := "2006-01-02"

	fromDate := start.In(timeutil.SGT).Format(dateLayout)
	toDate := end.In(timeutil.SGT).Format(dateLayout)

	var availableUntil string
	switch responseGroupedBy {
	case ResponseGroupedByMonth:
		resp, err := uportalbdl.Daily(ctx, uportalbdl.DailyRequest{
			AccNo:    accountNo,
			FromDate: fromDate,
			ToDate:   toDate,
		})
		if err != nil {
			return result, time.Time{}, time.Time{}, err
		}
		availableUntil = resp.ResponseData.AvailableUntil
		result = groupBDLDaily(ctx, resp.ResponseData.IntervalData)

	case ResponseGroupedByDay:
		resp, err := uportalbdl.HalfHourly(ctx, uportalbdl.HalfHourlyRequest{
			AccNo:    accountNo,
			FromDate: fromDate,
			ToDate:   toDate,
		})
		if err != nil {
			return result, time.Time{}, time.Time{}, err
		}
		availableUntil = resp.ResponseData.AvailableUntil
		result = groupBDLHalfHourly(ctx, resp.ResponseData.IntervalData)
	case ResponseGroupedByWeek:
		resp, err := uportalbdl.Daily(ctx, uportalbdl.DailyRequest{
			AccNo:    accountNo,
			FromDate: fromDate, // weekStartDate
			ToDate:   toDate,   // weekEndDate
		})
		if err != nil {
			return result, time.Time{}, time.Time{}, err
		}
		availableUntil = resp.ResponseData.AvailableUntil
		result = groupBDLWeekly(ctx, resp.ResponseData.IntervalData, start)

	default:
		return result, time.Time{}, time.Time{}, ErrGroupedByInvalid
	}

	// Default to FRC launch since we don't have the data from BDL microservice
	min := frcLaunchDate
	max, err := time.ParseInLocation(dateLayout, availableUntil, timeutil.SGT)
	if err != nil {
		max = timeutil.NowSGT()
	}
	return result, min, max, nil
}

// groupBDLDaily groups BDL daily interval data into a monthly responseGroupMap
func groupBDLDaily(ctx context.Context, data []uportalbdl.DailyIntervalData) ResponseGroupMap {
	logger := loglib.GetLogger(ctx)

	result := ResponseGroupMap{}
	var groupedByDate time.Time
	for _, it := range data {
		// Parse data point date
		dataPointDate, err := time.ParseInLocation("2006-01-02", it.FrequencyUsage, timeutil.SGT)
		if err != nil {
			logger.Errorf("[error] Invalid BDL daily data point date: %v", err)
			continue
		}

		// Get group (monthly) date
		// Set date to YYYY-MM-01 00:00:00
		groupedByDate = timeutil.Date(dataPointDate.Year(), dataPointDate.Month(), 1, 0, 0)

		// Find if group exists in seen group map
		// So that we can append/update the group information
		groupedByDateStr := groupedByDate.Format(time.RFC3339)
		groupedBy, ok := result[groupedByDateStr]
		if !ok {
			groupedBy = map[string]DataType{}
		}

		// Format data point date
		dataPointDateStr := dataPointDate.Format(time.RFC3339)
		dataPoint, ok := groupedBy[dataPointDateStr]
		if !ok {
			dataPoint = DataType{
				Date: dataPointDateStr,
			}
		}

		// Parse consumption value
		consumption, err := strconv.ParseFloat(it.CustomerReading, 64)
		if err != nil {
			// Default consumption to 0
			consumption = 0.0
		}

		// Set data point into group (monthly)
		dataPoint.Consumption = consumption
		groupedBy[dataPointDateStr] = dataPoint

		result[groupedByDateStr] = groupedBy
	}

	return result
}

// groupBDLHalfHourly groups BDL half-hourly interval data into a daily responseGroupMap
func groupBDLHalfHourly(ctx context.Context, data []uportalbdl.HalfHourlyIntervalData) ResponseGroupMap {
	logger := loglib.GetLogger(ctx)

	result := ResponseGroupMap{}
	for _, it := range data {
		// Parse data point date
		dataPointDate, err := time.ParseInLocation("2006-01-0215:04", it.DateField+it.FrequencyUsage, timeutil.SGT)
		if err != nil {
			logger.Errorf("[error] Invalid BDL half-hourly data point date: %v", err)
			continue
		}

		// Get group (daily) date
		// Set date to YYYY-MM-DD 00:00:00
		groupedByDate := timeutil.Date(dataPointDate.Year(), dataPointDate.Month(), dataPointDate.Day(), 0, 0)

		// Find if group exists in seen group map
		// So that we can append/update the group information
		groupedByDateStr := groupedByDate.Format(time.RFC3339)
		groupedBy, ok := result[groupedByDateStr]
		if !ok {
			groupedBy = map[string]DataType{}
		}

		// Format data point date
		dataPointDateStr := dataPointDate.Format(time.RFC3339)
		dataPoint, ok := groupedBy[dataPointDateStr]
		if !ok {
			dataPoint = DataType{
				Date: dataPointDateStr,
			}
		}

		// Parse consumption value
		consumption, err := strconv.ParseFloat(it.CustomerReading, 64)
		if err != nil {
			// Default consumption to 0
			consumption = 0.0
		}

		// Set data point into group (monthly)
		dataPoint.Consumption = consumption
		groupedBy[dataPointDateStr] = dataPoint

		result[groupedByDateStr] = groupedBy
	}

	return result
}

// groupBDLWeekly to map BDL daily interval data into a weekly responseGroupMap
func groupBDLWeekly(ctx context.Context, intervalData []uportalbdl.DailyIntervalData, weekStartDate time.Time) ResponseGroupMap {
	logger := loglib.GetLogger(ctx)
	result := ResponseGroupMap{}
	dataPoint := map[string]DataType{}
	for _, data := range intervalData {
		// Parse data point date
		dataTypeDate, err := time.ParseInLocation("2006-01-02", data.FrequencyUsage, timeutil.SGT)
		if err != nil {
			logger.Errorf("[groupBDLWeekly] Invalid BDL daily data point date: %v", err)
			continue
		}
		// Parse consumption value
		consumption, err := strconv.ParseFloat(data.CustomerReading, 64)
		if err != nil {
			// Default consumption to 0
			consumption = 0.0
		}

		// convert data point date to string
		dataTypeDateStr := dataTypeDate.Format(time.RFC3339)
		// init data type
		dataType := DataType{
			Date:        dataTypeDateStr,
			Consumption: consumption,
		}

		// Set data point into group (weekly)
		dataPoint[dataTypeDateStr] = dataType
	}

	// set data point map into response map
	result[weekStartDate.Format(time.RFC3339)] = dataPoint
	return result
}

