)

//RetrieveAverageBill returns average bill for consumption base on premise ID
func RetrieveAverageBill(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	bpDetails := bp.DetailsFromContext(ctx)
	premiseID := r.URL.Query().Get("premise_id")
	if premiseID == "" {
		return errPremiseID
	}

	premise, exist := bpDetails.GetPremises(premiseID)
	if !exist {
		return errPremise
	}

	bill, errBill := consumption.RetrieveBilledAverage(ctx, premise, 6)
	if errBill != nil {
		return errBill
	}
	web.RespondJSON(ctx, w, bill, nil)
	return nil
}

