		r.Get("/v3/ebill/switch", handler.Wrap(ebill.SwitchEligibility))
		r.Post("/v3/ebill/switch", handler.Wrap(ebill.Switch))

		// Account link completion
		r.Post("/v3/account/link/complete", handler.Wrap(account.LinkComplete))
	})
}

// internal is the OAuth2 machine-to-machine chi.Router.Group
func internal(r chi.Router) {
	// Middlewares
	// Access token middleware
	r.Use(basiciam.RequireAccessToken(auth0.JWKSKeyFunc))
	// Audience middleware
	r.Use(basiciam.RequireClaimAudience(auth0.AudM2M))

	// BP details
	r.With(basiciam.RequireClaimScope(auth0.ScopeM2MDeleteBPCache)).
		Delete("/v3/bp/cache", handler.Wrap(bp.RemoveCachedDetails))
	r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadBpDetails)).
		Get("/v3/bp/details", handler.Wrap(bp.GetBPDetails))

	// Payments
	r.Route("/v3/user", func(r chi.Router) {
		// Retrieve IAM_ID from formdata
		r.Use(bp.DetailsByFormMiddleware())

		// Bills
		r.Route("/bills", func(r chi.Router) {
			r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadBill))
			r.Get("/average", handler.Wrap(bill.RetrieveAverageBill))
		})
		// Chart
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadChart)).
			Post("/ami/charts", handler.Wrap(ami.Charts))
	})

	// AMI data
	r.Post("/v3/ami/download", handler.Wrap(ami.DownloadCSV))

	// Notifications
	r.Route("/v3/notify", func(r chi.Router) {
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MCreateNotification))
		r.Post("/bill/statement", handler.Wrap(billnotification.BroadcastPipe)) // Automic triggered notification job for billed statement
		r.Post("/bill/due", handler.Wrap(billnotification.BroadcastHdrTrl))     // Automic triggered notification job for bill due today
		r.Post("/bill/overdue", handler.Wrap(billnotification.BroadcastHdrTrl)) // Automic triggered notification job for bill overdue
		r.Post("/smrd/7d", handler.Wrap(smrdnotification.BroadcastSMRD7d))      // Automic triggered notification job for SMRD-7d reminder
		r.Post("/smrd/3d", handler.Wrap(smrdnotification.BroadcastSMRD3d))      // Automic triggered notification job for SMRD-3d reminder
		r.Post("/smrd/1d", handler.Wrap(smrdnotification.BroadcastSMRD1d))      // Automic triggered notification job for SMRD reminder
		r.Post("/payments", handler.Wrap(paymentnotification.Broadcast))        // Automic triggered notification job for payment success/failure
	})
	// Downtime schedules CRUD
	r.Route("/v3/downtimeschedules", func(r chi.Router) {
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadDowntime)).
			Get("/", handler.Wrap(downtime.HandleGet))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MCreateDowntime)).
			Post("/", handler.Wrap(downtime.HandlePost))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MUpdateDowntime)).
			Put("/", handler.Wrap(downtime.HandlePut))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadDowntime)).
			Get("/{id}", handler.Wrap(downtime.HandleGet))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MDeleteDowntime)).
			Delete("/{id}", handler.Wrap(downtime.HandleDelete))
	})

	// Shared premises feature toggle
	// Temporarily use this scope just to protect this endpoint and allow EVA Admin
	r.With(basiciam.RequireClaimScope(auth0.ScopeM2MCreateDowntime)).
		Put("/v3/feature/sharedpremises", handler.Wrap(bp.ToggleSharedPremisesFeature))
}

