// createJWTDetail creates a test JWT Detail
func createJWTDetail(ebsAccNo, msslAccNo string) bp.Details {
	result := bp.Details{
		Premises: []bp.PremisesType{
			{
				ID: "PREMISE",
				Accounts: []bp.AccountsType{
					{AccountNumber: "EBS_INACTIVE", System: frcpo.SystemEBS},
					{AccountNumber: "MSSL_INACTIVE", System: frcpo.SystemMSSL},
				},
			},
		},
		JWT: jwtClaims,
	}
	if ebsAccNo != "" {
		result.Premises[0].Accounts = append(result.Premises[0].Accounts, bp.AccountsType{AccountNumber: ebsAccNo, System: frcpo.SystemEBS})
	}
	if msslAccNo != "" {
		result.Premises[0].Accounts = append(result.Premises[0].Accounts, bp.AccountsType{AccountNumber: msslAccNo, System: frcpo.SystemMSSL})
	}
	return result
}

// createSubmitHTTPRequest is a helper method to create a http test request
func createSubmitHTTPRequest(ua string, bpDetails bp.Details, req SubmitRequest) (*httptest.ResponseRecorder, *http.Request) {
	r := httptest.NewRequest(http.MethodPost, "/v4/smrd", testhelpers.NewJSONReader(req))
	r = bp.ProvidesDetails(bpDetails, r)
	r.Header.Set("User-Agent", ua)
	w := httptest.NewRecorder()
	return w, r
