	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcportal/uportalaccountmanagement"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/oneupapi"
)

const SUBMIT_METER_QUEST = "A-SUBMIT-METER"

var nowSGT = timeutil.NowSGT

// Submit handles meter readings submission requests based on the provided
// submission token generated/created from GetDetails.
//
// The submission token should contain all meter read information
// necessary for the submission.
//
// The submit meter reading is a two-step process, where:
// Step 1: Get meter read details and check if it's within the submission period.
//
//	If yes, create/generate a submission token for the client to use on
//	submitting of meter readings
//
// Step 2: Submit user readings together with the submission token to ensure that
//
//	the execution of [Step 2] is valid based on the evaluation on [Step 1]
//
// Submit is the 2nd step to the submit meter reading process
func Submit(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	logger := loglib.GetLogger(ctx)
	now := timeutil.NowSGT()

	// Extract bp details
	bpDetails := bp.DetailsFromRequest(r)

	req := SubmitRequest{}
	if _, err := web.ParseAndLogJSONBody(logger, &req, r.Body); err != nil {
		return err
	}

	// Format and validate request
	if err := req.Format(); err != nil {
		return web.WithStack(err)
	}

	// Extract submit reading request
	userAgent, details, err := smrdSVC.ExtractSubmissionToken(req.SubmissionToken)
	if err != nil {
		return web.WithStack(smrdSVC.ErrSubmitTokenInvalid)
	}

	for accNo := range details {
		// Validate account number from submission_token
		if _, err := bpDetails.HasAccount(accNo); err != nil {
			return web.WithStack(err)
		}
	}

	// Validate user agent from submission_token
	if userAgent != r.UserAgent() {
		return web.WithStack(smrdSVC.ErrSubmitUAMismatch)
	}

	submitReqs := map[string]uportalaccountmanagement.SubmitMeterReadingRequest{}
	var nextMnr string
	for _, it := range req.Readings {
		// Find meter read details from submission token
		accNo, d, found := findMeterReadItem(details, it.MeterID)
		if found {
			// Construct submit reading request
			submitReq, ok := submitReqs[accNo]
			if !ok {
				submitReq = uportalaccountmanagement.SubmitMeterReadingRequest{
					AccNo: sap.StripAccountNo(accNo),
					MeterReadData: uportalaccountmanagement.SubmitMeterReadingMeterReadData{
						Item: []uportalaccountmanagement.SubmitMeterReadingItem{},
					},
				}
				submitReqs[accNo] = submitReq
			}

			// Extract next scheduled meter reading date from one of the meters
			// @Bertina - All utility types/meters will have same submission period
			if nextMnr == "" {
				nextMnr = d.NextMnr.String
			}

			// Validate upload parameters
			if err := validateUploadParams(it); err != nil {
				return web.WithStack(err)
			}

			// Parse user-submitted reading
			value, err := strconv.ParseFloat(it.Value, 64)
			if err != nil {
				return web.WithStack(smrdSVC.ErrSubmitReadingInvalid)
			}

			err = smrdSVC.ValidateSubmittedReading(value, d)
			if err != nil {
				return web.NewError(smrdSVC.ErrSubmitReadingInvalid, err.Error())
			}

			preDecValue, decValue, err := splitIntDecimal(d.UtilType.String, value, d.DecPlace.String)
			if err != nil {
				// Skip submit meter reading if dec place cannot be parsed
				smrdSVC.ReportErrors(err, accNo, fmt.Sprintf("%f", value))
				continue
			}

			// Construct submit meter reading request
			submitReq.MeterReadData.Item = append(submitReq.MeterReadData.Item, uportalaccountmanagement.SubmitMeterReadingItem{
				DeviceNo:    d.DeviceNo.String,
				UtilType:    d.UtilType.String,
				PreDecPlace: preDecValue,
				DecPlace:    decValue,
				Source:      uportalaccountmanagement.SubmitMeterReadingSource,
				ImageRefID:  it.ImageRefID,
				SubmitMode:  it.SubmitMode,
				ContactNo:   it.ContactNo,
			})
			submitReqs[accNo] = submitReq
		}
	}

	// Make meter reading submission request/s
	submitResps, err := submitMeterReadings(ctx, submitReqs)
	if err != nil {
		return err
	}

	// Iterate response list and craft error message if required
	for _, r := range submitResps {
		for _, it := range r.ResponseData.RespMeterReadData.Item {
			if it.Code != uportalaccountmanagement.SubmitMeterReadingCodeSuccess {
				logger.Errorf("Submit meter reading failed: %s", it.FailMsg)
				return web.NewError(smrdSVC.ErrSubmitFailed, it.FailMsg)
			}
		}
	}

	// Send meter submission challenge completion to 1up
	go func() {
		iamID := bpDetails.JWT.Sub
		logger.Infof("======== time now is %s\n", nowSGT().Format(time.RFC3339))
		_, err = oneupapi.CompleteActivity(ctx, oneupapi.CompleteActivityRequest{
			Variables: oneupapi.CompleteActivityVariables{
				AccountID:   bpDetails.JWT.Sub,
				QuestID:     SUBMIT_METER_QUEST,
				CompletedAt: nowSGT().Format(time.RFC3339),
			},
		})
		if err != nil && err != oneupapi.ErrCompleteActivityMaxAttempts {
			ravenerrors.Report(err, map[string]string{
				"iam_id":   iamID,
				"quest_id": SUBMIT_METER_QUEST,
			})
		}
	}()

	// Construct response
	nextSmrdMessage := ""
	nextSmrdHTMLMessage := ""
	// Get submission period
	nextMnrDate, err := smrdSVC.ConvertDateFormat(nextMnr)
	if err == nil {
		start, end, err := smrdSVC.CalculateSubmissionPeriod(nextMnrDate, smrdSVC.CategoryLookup[meterreaddetails.MroFlagEstimated])
		if err == nil && !start.IsZero() && !end.IsZero() {
			nextSmrdMessage = fmt.Sprintf("\n\nYour next submission window is between %s and %s.", start.Format("02 Jan 2006 3PM"), end.Format("02 Jan 2006 3PM"))
			nextSmrdHTMLMessage = fmt.Sprintf("<br/><br/>Your next submission window is between <b>%s and %s</b>.", start.Format("02 Jan 2006 3PM"), end.Format("02 Jan 2006 3PM"))
		}
	}
	resp := smrdSVC.SubmitResponse{
		Message:     fmt.Sprintf("If our meter reader has read your meters, your meter readings will not be used for billing.%s", nextSmrdMessage),
		HTMLMessage: fmt.Sprintf("If our meter reader has read your meters, your meter readings will not be used for billing.%s", nextSmrdHTMLMessage),
	}
	// checks if successful submission is an elec submission and send email confirmation in background
	if elecSubmission, ok := getElecSubmission(submitResps); ok {
		newCtx := context.Background()
		newCtx = loglib.SetLogger(newCtx, logger)
		go smrdSVC.ProcessMeterSubmissionForConfirmationEmail(newCtx, *bpDetails, now, submitReqs, elecSubmission)
	}

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

func submitMeterReadings(ctx context.Context, reqs map[string]uportalaccountmanagement.SubmitMeterReadingRequest) ([]uportalaccountmanagement.SubmitMeterReadingResponse, error) {
	result := []uportalaccountmanagement.SubmitMeterReadingResponse{}

	if len(reqs) <= 0 {
		return nil, web.WithStack(smrdSVC.ErrSubmitNoValidReadings)
	}

	g := &errgroup.Group{}
	for _, req := range reqs {
		req := req
		g.Go(func() error {
			// Submit meter readings
			resp, err := uportalaccountmanagement.SubmitMeterReading(ctx, req)
			if err != nil {
				return err
			}

			result = append(result, resp)
			return nil
		})
	}

	if err := g.Wait(); err != nil {
		return nil, err
	}

	return result, nil
}

// findMeterReadItem finds the meterreadingdetails.ItemType in the array based on the provided device number
func findMeterReadItem(arr smrdSVC.SubmissionDetails, deviceNo string) (string, meterreaddetails.ItemType, bool) {
	for accNo, items := range arr {
		for _, it := range items {
			if deviceNo == it.DeviceNo.String {
				return accNo, it, true
			}
		}
	}
	return "", meterreaddetails.ItemType{}, false
}

// splitIntDecimal splits a float value's integer and decimal portion for submit meter reading
func splitIntDecimal(sapUtilType string, value float64, expectedDecPlace string) (string, string, error) {
	var integer, decimal string

	decPlace, err := strconv.Atoi(expectedDecPlace)
	if err != nil {
		decPlace = 0
		// TODO: Add dec place validation if we're sure that WE SHOULD base
		// splitting logic on retrieve meter read details response
		// As of 23/03, UPortal is not sure if that's the case, hence the
		// hardcoded logic below to set "" if elec or gas
		// return "", "", errors.New("Invalid decimal count")
	}

	// Convert float value to int considering the expected # of decimal places
	// Sample:
	// value = 100.52
	// expectedDecPlace = 4
	// result = 1005200
	valueInt := int(value * math.Pow10(decPlace))

	valueStr := strconv.Itoa(valueInt)
	decIndex := len(valueStr) - decPlace
	integer = valueStr[:decIndex]
	decimal = valueStr[decIndex:]

	if integer == "" {
		integer = "0"
	}
	if decimal == "" {
		decimal = "0"
	}

	// remove decimal if utility type is elect or gas
	// TODO: Change dec place validation logic if we're sure that WE SHOULD base
	// splitting logic on retrieve meter read details response
	// As of 23/03/18, UPortal is not sure if that's the case, hence the
	// hardcoded logic below to set "" if elec or gas
	// Otherwise, would've been `if dec_place = 0 then ""`, rather than utility type-based
	switch sapUtilType {
	case meterreaddetails.UtilTypeElectric, meterreaddetails.UtilTypeGas:
		decimal = ""
	}

	return integer, decimal, nil
}

// Format formats and validates the request fields
func (s *SubmitRequest) Format() error {
	s.SubmissionToken = strings.TrimSpace(s.SubmissionToken)

	if s.SubmissionToken == "" {
		return smrdSVC.ErrSubmitTokenInvalid
	}

	if len(s.Readings) <= 0 {
		return smrdSVC.ErrSubmitNoReadings
	}
	return nil
}

// getElecSubmission iterate response list and check if elec exists
func getElecSubmission(submitResps []uportalaccountmanagement.SubmitMeterReadingResponse) (uportalaccountmanagement.SubmitMeterReadingRespItem, bool) {
	for _, r := range submitResps {
		for _, it := range r.ResponseData.RespMeterReadData.Item {
			if it.UtilType == meterreaddetails.UtilTypeElectric {
				return it, true
			}
		}
	}

	return uportalaccountmanagement.SubmitMeterReadingRespItem{}, false
}

func validateUploadParams(it ReadingsType) error {
	err := smrdSVC.ValidateSubmitMode(it.SubmitMode)
	if err != nil {
		return web.WithStack(err)
	}

	err = smrdSVC.ValidateContactNo(it.ContactNo)
	if err != nil {
		return web.WithStack(err)
	}
	return nil
}

package account

import (
	"context"
	"net/http"

	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/authc"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
)

// UserIAMAssociation stores all SAP accounts association grouped by IAM ID
type UserIAMAssociation struct {
	IamID    string                  `json:"iam_id"`
	Accounts []SAPAccountAssociation `json:"accounts"`
}

// SAPAccountAssociation stores bp number, account number association
type SAPAccountAssociation struct {
	BpNumber      string   `json:"bp_number"`
	AccountNumber string   `json:"account_number"`
	Source        string   `json:"source"`
	Utilities     []string `json:"utilities"`
	Active        bool     `json:"active"`
	Owner         bool     `json:"owner"`
}

// RetrieveAccountsByIAM handles requests to retrieve all non-retailer accounts by IAM ids
func RetrieveAccountsByIAM(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	// Get query params
	iamIDs := r.URL.Query()["iam_ids"]
	if len(iamIDs) <= 0 {
		return web.WithStack(ErrIamIDsEmpty)
	}

	details, err := retrieveBpDetails(ctx, iamIDs)
	if err != nil {
		return web.WithStack(err)
	}

	results := extractNonRetailerAccounts(details)

	web.RespondJSON(ctx, w, results, nil)
	return nil
}

// retrieveBpDetails retrieves the account details of the given iamIDs, including shared premise users
func retrieveBpDetails(ctx context.Context, iamIDs []string) ([]bp.Details, error) {
	results := []bp.Details{}

	for _, iamID := range iamIDs {
		details, err := bp.LoadDetails(ctx, authc.JWTClaims{Sub: iamID}, true)
		if err != nil {
			return []bp.Details{}, web.WithStack(err)
		}
		results = append(results, details)
	}

	return results, nil
}

// Details.Premises.Accounts contains only accounts under SP billing, including XOBR-C,
// thus do not require further filtering
// extractNonRetailerAccounts loops given bp.Details array and return only non-retailer accounts
func extractNonRetailerAccounts(details []bp.Details) []UserIAMAssociation {
	results := []UserIAMAssociation{}

	for _, d := range details {
		ua := UserIAMAssociation{
			IamID: d.JWT.Sub,
		}

		allAccounts := []SAPAccountAssociation{}
		for _, p := range d.Premises {
			for _, acc := range p.Accounts {
				allAccounts = append(allAccounts, SAPAccountAssociation{
					AccountNumber: acc.AccountNumber,
					BpNumber:      acc.BpNumber,
					Source:        acc.System,
					Utilities:     acc.Utilities,
					Active:        acc.AccountStatus == frcpo.AccountStatusActive,
					Owner:         p.SharedResourceDetails.Owner,
				})
			}
		}
		ua.Accounts = allAccounts
		results = append(results, ua)
	}

	return results
}

