				{System: frcpo.SystemEBS, Utilities: []string{}, PremiseNumber: expectedSharedID},
			},
		},
	}
	cleanUpCache := func() { RemoveCache(expectedSharedID) }

	testCases := []struct {
		cached bool
	}{
		{cached: true},
		{cached: false},
	}

	for _, tc := range testCases {
