					OemEligible: false,
					SharedResourceDetails: SharedResourceDetailsType{
						Owner:      true,
						OwnerIamID: "IAMID",
					},
					Accounts: []AccountsType{
						{AccountStatus: frcpo.AccountStatusActive, AccountNumber: "MSSL", System: frcpo.SystemMSSL},
					},
				},
				{
					ID:          "3",
					Active:      false,
					Address:     "777 EBS RD 077777",
					OemEligible: false,
					SharedResourceDetails: SharedResourceDetailsType{
						Owner:      true,
						OwnerIamID: "IAMID",
					},
					Accounts: []AccountsType{
						{AccountStatus: frcpo.AccountStatusInactive, AccountNumber: "INACTIVE", System: frcpo.SystemEBS},
					},
				},
				{
					ID:          "4",
					Active:      true,
					Address:     "444 SHARED RD 044444",
					OemEligible: false,
					SharedResourceDetails: SharedResourceDetailsType{
						Owner:      false,
						OwnerIamID: "SHAREDIAMID",
					},
					Accounts: []AccountsType{
						{AccountStatus: frcpo.AccountStatusInactive, AccountNumber: "EBS", System: frcpo.SystemEBS},
					},
