		// Prep fixtures:
		// Pilot
		pilot := models.PilotUser{IamID: given.JWT.Sub, SharePremises: true}
		require.NoError(t, pilot.Insert(context.TODO(), tx, boil.Infer()))

		r = ProvidesDetails(given, r)
		w := httptest.NewRecorder()
