)

func TestOutstandingBySystem(t *testing.T) {
	msslAcc1, ebsAcc1 := "MSSL_ACC1", "EBS_ACC1"
	testCases := []struct {
		givenAccountNo string
		givenSystem    string
		expected       OutstandingAmount
	}{
		{
			givenAccountNo: msslAcc1,
			givenSystem:    frcpo.SystemMSSL,
			expected: OutstandingAmount{
				AccountNumber: msslAcc1,
				Amount:        13842,
			},
		},
		{
			givenAccountNo: ebsAcc1,
			givenSystem:    frcpo.SystemEBS,
			expected: OutstandingAmount{
				AccountNumber: ebsAcc1,
				Amount:        2347,
			},
		},
	}

	for i, tc := range testCases {
		tc := tc
		t.Run(strconv.Itoa(i), func(t *testing.T) {
			// Given:
			query := url.Values{}
			query.Add("account_number", tc.givenAccountNo)
			query.Add("system", tc.givenSystem)

			r := httptest.NewRequest(http.MethodGet, "/v4/accounts/outstanding?"+query.Encode(), nil)
			w := httptest.NewRecorder()

			// Mocks:
			ctx := r.Context()
			ctx = mockOpenamountResp(ctx, frcpo.SystemMSSL, msslAcc1, openamount.Response{
				YOpenAmnt: sapjson.FromString("138.42"),
			})
			ctx = mockOpenamountResp(ctx, frcpo.SystemEBS, ebsAcc1, openamount.Response{
				YOpenAmnt: sapjson.FromString("23.47"),
			})
			r = r.WithContext(ctx)

			// When:
			err := OutstandingBySystem(w, r)

			// Then:
			require.NoError(t, err)
			resp := OutstandingAmount{}
			testhelpers.ParseJSONResponse(t, w.Result(), &resp)
			require.Equal(t, tc.expected.AccountNumber, resp.AccountNumber)
			require.Equal(t, tc.expected.Amount, resp.Amount)
		})
	}
}

func TestOutstandingBySystem_Error(t *testing.T) {
	testCases := []struct {
		givenAccountNo string
		givenSystem    string
		mockedResp     openamount.Response
		mockedErr      error
		expected       *web.Error
	}{
		{
			givenAccountNo: "VALID_ACC",
			givenSystem:    "",
			expected:       ErrSystemEmpty,
		},
		{
			givenAccountNo: "",
			givenSystem:    "VALID_SYS",
			expected:       ErrAccountNumberEmpty,
		},
		{
			givenAccountNo: "VALID",
			givenSystem:    frcpo.SystemEBS,
			mockedResp: openamount.Response{
				YOpenAmnt: sapjson.FromString("WRONG_OPEN_AMOUNT"),
			},
			mockedErr: nil,
			expected:  ErrOpenAmountInvalid,
		},
		{
			givenAccountNo: "VALID",
			givenSystem:    frcpo.SystemEBS,
			mockedResp: openamount.Response{
				YOpenAmnt: sapjson.FromString("Not implemented"),
			},
			mockedErr: &web.Error{Code: "moar_error", Status: http.StatusNotImplemented, Desc: "moar_error"},
			expected:  &web.Error{Code: "moar_error", Status: http.StatusNotImplemented, Desc: "moar_error"},
		},
	}

	for i, tc := range testCases {
		tc := tc
		t.Run(strconv.Itoa(i), func(t *testing.T) {
			// Given:
			query := url.Values{}
			query.Add("account_number", tc.givenAccountNo)
			query.Add("system", tc.givenSystem)

			r := httptest.NewRequest(http.MethodGet, "/v4/accounts/outstanding?"+query.Encode(), nil)
			w := httptest.NewRecorder()

			// Mocks:
			if (tc.mockedResp != openamount.Response{}) {
				ctx := r.Context()
				ctx = openamountbroker.MockRequestResponse(ctx, frcpo.SystemEBS, nil, tc.mockedResp, tc.mockedErr)
				r = r.WithContext(ctx)
			}

			// When:
			err := OutstandingBySystem(w, r)

			// Then:
			testhelpers.AssertWebError(t, tc.expected.Status, tc.expected.Code, err)
		})
	}
}

func mockOpenamountResp(ctx context.Context, system, accNo string, expectedResp openamount.Response) context.Context {
	req := &openamount.Request{
		MtSuspenseoutstandingamountreadrequest: openamount.MtSuspenseoutstandingamountreadrequestType{
			Accountno: accNo,
		},
	}

	ctx = openamountbroker.MockRequestResponse(ctx, system, req, expectedResp, nil)
	return ctx
}

