import (
	"context"
	"fmt"
	"net/http"
	"strconv"

	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/numutil"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/broker/openamountbroker"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs/openamount"
)

// OutstandingAmount is the struct that holds the outstanding amount payable for the account number
type OutstandingAmount struct {
	AccountNumber string `json:"account_number"`
	Amount        int64  `json:"amount"`
}

// OutstandingBySystem handle requests to retrieve the oustanding amount for the account number and system pair
func OutstandingBySystem(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	accNo := r.URL.Query().Get("account_number")
	if accNo == "" {
		return ErrAccountNumberEmpty
	}
	system := r.URL.Query().Get("system")
	if system == "" {
		return ErrSystemEmpty
	}

	result, err := retrieveOutstandingAmount(ctx, accNo, system)
	if err != nil {
		return web.WithStack(err)
	}

	web.RespondJSON(ctx, w, result, nil)
	return nil
}

// retrieveOutstandingAmount returns outstanding bill amount for the given account and system pair
// reference from internal/app/v4/payment/outstanding.go#retrieveOpenAmount
func retrieveOutstandingAmount(ctx context.Context, accNo, system string) (OutstandingAmount, error) {
	resp, err := openamountbroker.MakeRequest(ctx, system, openamount.Request{
		MtSuspenseoutstandingamountreadrequest: openamount.MtSuspenseoutstandingamountreadrequestType{
			Accountno: accNo,
		},
	})
	if err != nil {
		return OutstandingAmount{}, err
	}

	if resp.ErrorCode.String != "" {
		return OutstandingAmount{}, web.NewError(ErrOpenAmountRetrieve, fmt.Sprintf("Outstanding amount response error code: %v", resp.ErrorCode.String))
	}

	_, err = strconv.ParseFloat(resp.YOpenAmnt.String, 64)
	if err != nil {
		return OutstandingAmount{}, web.NewError(ErrOpenAmountInvalid, err.Error())
	}

	amountInt, err := numutil.DollarStringToCentsInt(resp.YOpenAmnt.String)
	if err != nil {
		return OutstandingAmount{}, web.NewError(ErrOpenAmountInvalid, err.Error())
	}

	return OutstandingAmount{
		AccountNumber: accNo,
		Amount:        amountInt,
	}, nil
}

