// RemoveCachedDetails handles requests to remove cached details for the provided keys in the request
func RemoveCachedDetails(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()
	logger := loglib.GetLogger(ctx)

	var req RemoveCachedDetailsRequest
	if _, err := web.ParseAndLogJSONBody(logger, &req, r.Body); err != nil {
