const (
	// QuestID is the quest ID for link utilities
	QuestID = "A-LINK-UTILITIES"
)

var nowSGT = timeutil.NowSGT

// LinkComplete handles completion acknowledgement for account linking
func LinkComplete(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	bpDetails := bp.DetailsFromRequest(r)
	if bpDetails == nil {
		return web.WithStack(ErrAccountNotLinked)
	}

	// Send activity completion to 1up
	_, err := oneupapi.CompleteActivity(ctx, oneupapi.CompleteActivityRequest{
		Variables: oneupapi.CompleteActivityVariables{
			AccountID:   bpDetails.JWT.Sub,
			QuestID:     QuestID,
			CompletedAt: nowSGT().Format(time.RFC3339),
		},
	})
	if err != nil {
		return web.WithStack(err)
	}

	web.RespondJSON(ctx, w, web.Success{Message: "Successfully completed link utilities challenge."}, nil)
	return nil
}

