func TestRetrieveEMDS(t *testing.T) {
	testCases := []struct {
		groupedBy string
	}{
		{ResponseGroupedByDay},
		{ResponseGroupedByMonth},
	}

	for _, tc := range testCases {
		t.Run(tc.groupedBy, func(t *testing.T) {
			// Given:
			ctx := context.Background()
			accNos := []string{"ACC1"}
			start := timeutil.Date(2018, 1, 1, 0, 0)
			end := timeutil.Date(2018, 5, 1, 0, 0)

			// Mocks:
			switch tc.groupedBy {
			case ResponseGroupedByDay:
				ctx = emds.MockAMIHalfHourlyByDay(ctx,
					&emds.AMIHalfHourlyByDayRequest{
						AccountNumbers: accNos,
						StartDate:      start.Format("2006-01-02"),
						EndDate:        end.Format("2006-01-02"),
					},
					emds.AMIHalfHourlyByDayResponse{
						AccountsList: []emds.AMIHalfHourlyByDayAccountsList{
							{
								HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
									{Date: "2018-03-01", HalfHourlyReadings: evenHourReadings},
									{Date: "2018-03-02", HalfHourlyReadings: evenHourReadings},
								},
							},
						},
					}, nil)
			case ResponseGroupedByMonth:
				ctx = emds.MockAMIDailyByMonth(ctx,
					&emds.AMIDailyByMonthRequest{
						AccountNumbers: accNos,
						StartMonth:     start.Format("2006-01"),
						EndMonth:       end.Format("2006-01"),
					},
					emds.AMIDailyByMonthResponse{
						AccountsList: []emds.AMIDailyByMonthAccountsList{
							{
								DailyByMonthDetails: []emds.AMIDailyByMonthDailyByMonthDetails{
									{Month: "2018-03", DailyReadings: evenDayReadings},
									{Month: "2018-04", DailyReadings: evenDayReadings},
								},
							},
						},
					}, nil)
			}

			// When:
			result, err := retrieveEMDS(ctx, accNos, start, end, tc.groupedBy)

			// Then:
			assert.NoError(t, err)
			assert.Len(t, result, 2)

			switch tc.groupedBy {
			case ResponseGroupedByDay:
				assert.Len(t, result["2018-03-01T00:00:00+08:00"], 24)
				assert.Len(t, result["2018-03-02T00:00:00+08:00"], 24)
			case ResponseGroupedByMonth:
				assert.Len(t, result["2018-03-01T00:00:00+08:00"], 15)
				assert.Len(t, result["2018-04-01T00:00:00+08:00"], 15)
			default:
				assert.FailNow(t, "invalid response grouped by")
			}
		})
	}
}
func TestAggregateHalfHourlyReadings(t *testing.T) {
	// Given:
	ctx := context.Background()
	given := []emds.AMIHalfHourlyByDayAccountsList{
		{
			AccountNumber: "M03 D[01,15] H[EVEN]",
			HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
				{Date: "2018-03-01", HalfHourlyReadings: evenHourReadings},
				{Date: "2018-03-15", HalfHourlyReadings: evenHourReadings},
				{Date: "INVALID", HalfHourlyReadings: evenHourReadings},
			},
		},
		{
			AccountNumber: "M03 D[01,15] H[ODD]",
			HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
				{Date: "2018-03-01", HalfHourlyReadings: oddHourReadings},
				{Date: "2018-03-15", HalfHourlyReadings: oddHourReadings},
				{Date: "INVALID", HalfHourlyReadings: evenHourReadings},
			},
		},
		{
			AccountNumber: "M03 D[15,30] H[EVEN]",
			HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
				{Date: "2018-03-15", HalfHourlyReadings: evenHourReadings},
				{Date: "2018-03-30", HalfHourlyReadings: evenHourReadings},
				{Date: "INVALID", HalfHourlyReadings: evenHourReadings},
			},
		},
		{
			AccountNumber: "M03 D[15,30] H[ODD]",
			HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
				{Date: "2018-03-15", HalfHourlyReadings: oddHourReadings},
				{Date: "2018-03-30", HalfHourlyReadings: oddHourReadings},
				{Date: "INVALID", HalfHourlyReadings: evenHourReadings},
			},
		},
		{
			AccountNumber: "12 D[05] H[EVEN]",
			HalfHourlyByDayDetails: []emds.AMIHalfHourlyByDayHalfHourlyByDayDetails{
				{Date: "2018-12-05", HalfHourlyReadings: evenHourReadings},
				{Date: "INVALID", HalfHourlyReadings: evenHourReadings},
			},
		},
	}

	// Expected:
	// | Day        | Data points | Value | Remarks                          |
	// |:----------:|:-----------:|:-----:|:--------------------------------:|
	// | 2018-03-01 | 48          | 1.0   | Even and odd merged              |
	// | 2018-03-15 | 48          | 2.0   | Aggregated, even and odd merged  |
	// | 2018-03-30 | 48          | 1.0   | Even and odd merged              |
	// | 2018-12-05 | 24          | 1.0   | No merge done                    |

	// When:
	result := aggregateHalfHourlyReadings(ctx, given)

	// Then:
	assert.Len(t, result, 4)
	for k, dataGroup := range result {

		switch k {
		case "2018-03-01T00:00:00+08:00",
			"2018-03-30T00:00:00+08:00":
			assert.Len(t, dataGroup, 48)
			for dk, dv := range dataGroup {
				_, err := time.Parse(time.RFC3339, dk)
				assert.NoError(t, err)
				assert.Equal(t, 1.0, dv.Consumption)
			}
		case "2018-03-15T00:00:00+08:00":
			assert.Len(t, dataGroup, 48)
			for dk, dv := range dataGroup {
				_, err := time.Parse(time.RFC3339, dk)
				assert.NoError(t, err)
				assert.Equal(t, 2.0, dv.Consumption)
			}
		case "2018-12-05T00:00:00+08:00":
			assert.Len(t, dataGroup, 24)
			for dk, dv := range dataGroup {
				_, err := time.Parse(time.RFC3339, dk)
				assert.NoError(t, err)
				assert.Equal(t, 1.0, dv.Consumption)
			}
		default:
			assert.FailNow(t, "should not contain keys/dates other than expected")
		}
	}
}

