)

// RetrieveDetails handles requests to retrieve bp details
func RetrieveDetails(w http.ResponseWriter, r *http.Request) error {
	ctx := r.Context()

	// Get details from request
	details := DetailsFromRequest(r)
	if details == nil {
		return web.WithStack(ErrRetrieveDetails)
	}

	// Populate uncached details
	resp, err := PopulateUncachedDetails(ctx, *details)
	if err != nil {
		return web.WithStack(err)
	}

	web.RespondJSON(ctx, w, resp, nil)
	return nil
}

// PopulateUncachedDetails populates the fields in details provided (from cache) that are uncached
// - Pilot
func PopulateUncachedDetails(ctx context.Context, details Details) (Details, error) {
	err := db.Tx(ctx, db.TxFromContext(ctx), func(tx db.Transactor) error {
		// Retrieve pilot user
		pilot, err := models.FindPilotUser(context.TODO(), tx, details.JWT.Sub)
		if err == sql.ErrNoRows || pilot == nil {
			return nil
		}
		if err != nil {
			return web.NewError(ErrRetrievePilotUser, err.Error())
		}
		// Populate pilot access
		details.Pilot.SharePremises = pilot.SharePremises
		return nil
	}, 3)
	if err != nil {
		return details, web.WithStack(err)
	}

	return details, nil
}

