import (
	"context"
	"fmt"
	"log"
	"os"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/golang/ravenerrors"
	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/redis"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs/meterinstallationdetails"
	"github.com/pkg/errors"
)

const (
	cacheKeyPrefixSRLPMech = "srlpmech_"
)

var (
	client *redis.Client
)

func init() {
	var err error
	client, err = redis.NewClient(context.Background(), os.Getenv("REDIS_URL"))
	if err != nil {
		log.Fatalf("%s", errors.Wrap(err, "redis"))
	}
}

// hasSRLPMechMeter returns true if account has an active SRLP mechanical (cumulative) meter
func hasSRLPMechMeter(ctx context.Context, p bp.PremisesType) (bool, error) {
	logger := loglib.GetLogger(ctx)

	// Get active EBS account
	ebsAcc, ok := p.GetActiveEBSAccount()
	if !ok {
		return false, web.WithStack(ErrNoActiveAccounts)
	}
	ebsAccNo := ebsAcc.AccountNumber

	// Check if flag is already in the cache
	if isSRLPMech, ok := getSRLPMechFlagCache(ebsAccNo); ok {
		logger.Debugf("Retrieved cached SRLP mechanical meter flag for %v: %t", ebsAccNo, isSRLPMech)
		// Return value from cache
		return isSRLPMech, nil
	}

	logger.Debugf("Loading SRLP mechanical meter flag %v", ebsAccNo)
	// Retrieve meter installation details for account number
	resp, err := meterinstallationdetails.MakeRequest(ctx, meterinstallationdetails.Request{
		AccountNo: ebsAccNo,
	})
	if err != nil {
		return false, err
	}

	// Iterate meter installation details
	var isSRLPMech bool
	now := time.Now()
	for _, it := range resp.MtInstallationmeterreadresponse.Item.Array {
		// Check meter installation utility type
		if it.Division.String != meterinstallationdetails.DivisionElectric {
			// Only elec supported. Skip if not supported
			continue
		}

		if !meterinstallationdetails.IsMeterActive(it, now) {
			// Skip inactive meter
			continue
		}

		// Evaluate if meter is not AMI (Mechanical) and SRLP
		if !meterinstallationdetails.IsAMI(it) && meterinstallationdetails.IsSRLP(it) {
			isSRLPMech = true
			break
		}
	}

	// Save flag to cache
	if err := saveSRLPMechFlagCache(ebsAccNo, isSRLPMech); err != nil {
		logger.Errorf("[bp/cache] Error saving SRLP mechanical to cache: %s", err.Error())
		ravenerrors.Report(err, map[string]string{
			"account_number": ebsAccNo,
		})
	}

	return isSRLPMech, nil
}

// getSRLPMechFlagCache gets the flag to indicate if a particular account number is using SRLP mechanical meter
func getSRLPMechFlagCache(accNo string) (bool, bool) {
	val, err := client.Get(cacheKeyPrefixSRLPMech + accNo)
	if err != nil {
		return false, false
	}
	return (val == "true"), true
}

// saveSRLPMechFlagCache saves the SRLP mechanical flag into the cache
func saveSRLPMechFlagCache(accNo string, flag bool) error {
	err := client.Set(cacheKeyPrefixSRLPMech+accNo, fmt.Sprintf("%t", flag), time.Duration(24*time.Hour))
	if err != nil {
		return web.NewError(ErrCacheSave, err.Error())
	}
	return nil
}

// removeSRLPMechFlagCache removes/deletes the SRLP mechanical flag from the cache
func removeSRLPMechFlagCache(accNo string) error {
	_, err := client.Del(cacheKeyPrefixSRLPMech + accNo)
	if err != nil {
		return web.NewError(ErrCacheRemove, err.Error())
	}
	return nil
}

package bp

import (
	"context"
	"sort"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/loglib"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/utilities"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs/meterinstallationdetails"
	"golang.org/x/sync/errgroup"
)

var (
	meterInstallationUtilityLookup = map[string]string{
		meterinstallationdetails.DivisionElectric: utilities.TypeElectric,
		meterinstallationdetails.DivisionGas:      utilities.TypeGas,
		meterinstallationdetails.DivisionWater:    utilities.TypeWater,
	}
)

type mdChanData struct {
	premisesID        string
	amiElec           bool
	intervalUtilities []string
	srlp              bool
}

// retrieveMeterDetails retrieves the premises's meter installation details (i.e. interval utilities, SMMU, AMI, rate category)
func retrieveMeterDetails(ctx context.Context, g *errgroup.Group, accType string, p PremisesType, data mdChanData, out chan mdChanData) {
	logger := loglib.GetLogger(ctx)

	var acc AccountsType
	var ok bool
	if accType == frcpo.SystemMSSL {
		acc, ok = p.GetActiveMSSLAccount()
	} else {
		acc, ok = p.GetActiveEBSAccount()
	}
	if !ok {
		return
	}

	data.intervalUtilities = []string{}

	g.Go(func() error {
		// Retrieve meter installation details for account number
		resp, err := meterinstallationdetails.MakeRequest(ctx, meterinstallationdetails.Request{
			AccountNo: acc.AccountNumber,
		})
		if err != nil {
			logger.Errorf("Encountered error retrieving meter installation details for %s: %s", acc.AccountNumber, err.Error())
			return err
		}
		if resp.MtInstallationmeterreadresponse.Errmsg.String != "" {
			logger.Errorf("Encountered error retrieving meter installation details for %s: %s", acc.AccountNumber, resp.MtInstallationmeterreadresponse.Errmsg.String)
			// Commented out erroring out (basically ignore and log error for now) and proceed to evaluate the list of meters
			// TODO: Ask Subash (or whoever in ITD) what does "Invalid Input Parameter" mean
			// return errors.New(resp.MtInstallationmeterreadresponse.Errmsg.String)
		}
		meters := resp.MtInstallationmeterreadresponse.Item.Array

		// Populate meter interval utilities
		intervalUtilities, err := evaluateIntervalUtilities(ctx, acc, meters)
		if err != nil {
			return err
		}
		data.intervalUtilities = intervalUtilities

		m, ok := findActiveElecMeter(meters)
		if ok {
			data.amiElec = meterinstallationdetails.IsAMI(m)
			data.srlp = meterinstallationdetails.IsSRLP(m)
		}

		out <- data
		return nil
	})
}

// findActiveElecMeter finds the active elec meter from the array provided
func findActiveElecMeter(meters []meterinstallationdetails.ItemType) (meterinstallationdetails.ItemType, bool) {
	now := time.Now()
	for _, it := range meters {
		// Check meter installation utility type
		utilityType, ok := meterInstallationUtilityLookup[it.Division.String]
		if !ok {
			// Skip unsupported/unknown utility type
			continue
		}

		// Active elec meter
		if utilityType == utilities.TypeElectric &&
			meterinstallationdetails.IsMeterActive(it, now) {
			return it, true
		}
	}
	return meterinstallationdetails.ItemType{}, false
}

// evaluateIntervalUtilities evaluates the utilities for an account that has interval data (half-hourly)
func evaluateIntervalUtilities(ctx context.Context, acc AccountsType, meters []meterinstallationdetails.ItemType) ([]string, error) {
	result := []string{}
	// Iterate meter installation details
	now := time.Now()
	for _, it := range meters {
		// Check meter installation utility type
		utilityType, ok := meterInstallationUtilityLookup[it.Division.String]
		if !ok {
			// Skip unsupported/unknown utility type
			continue
		}

		// Only allows meters on either:
		// - AMI
		// - SRLP rate category
		// Note that `interval_utilities` indicates that the following utilities can retrieve half-hourly data from BDL
		// As of 20190115, it is no longer limited to AMI alone, but we're also opening it up for SRLP meters (even mechanical)
		if !meterinstallationdetails.IsAMI(it) && !meterinstallationdetails.IsSRLP(it) {
			// Skip invalid meter configuration
			continue
		}

		// Clean-up outdated/replaced AMI meter
		if !meterinstallationdetails.IsMeterActive(it, now) {
			// Skip inactive meter
			continue
		}

		// Register AMI meter
		result = append(result, utilityType)
	}

	// Sort utilities
	sort.Strings(result)
	return result, nil
}

