import (
	"net/http"

	"code.in.spdigital.sg/sp-digital/golang/ravenerrors"
	web "code.in.spdigital.sg/sp-digital/golang/web.v2"
	"code.in.spdigital.sg/sp-digital/golang/web.v2/middleware"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/authc"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/auth0"
)

// DetailsByJWTMiddleware serves as a middleware that populates the bp details from JWT into the context
func DetailsByJWTMiddleware() middleware.Adapter {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			var err error
			ctx := r.Context()
			// Get BP details from context (@see authc.Middleware)
			jwtClaims := authc.JWTFromContext(ctx)
			if jwtClaims == nil {
				err = web.WithStack(auth0.ErrAccessToken)
				ravenerrors.Report(err, web.GetRequestContext(ctx).ToRequestInfo())
				web.RespondJSON(ctx, w, err, nil)
				return
			}

			// Sets the cached bp details or loads new bp details into the cache if not present, and into the context
			if ctx, err = LoadDetailsToContext(ctx, *jwtClaims); err != nil {
				ravenerrors.Report(err, web.GetRequestContext(ctx).ToRequestInfo())
				web.RespondJSON(ctx, w, err, nil)
				return
			}
			r = r.WithContext(ctx)

			next.ServeHTTP(w, r)
		})
	}
}

// DetailsByFormMiddleware serves as a middleware that populates the bp details from the request's iam_id into the context
func DetailsByFormMiddleware() middleware.Adapter {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			var err error
			ctx := r.Context()
			// Populate BP details with IAM ID in form
			iamID := r.FormValue("iam_id")
			if iamID == "" {
				err = web.WithStack(ErrIamIDEmpty)
				ravenerrors.Report(err, web.GetRequestContext(ctx).ToRequestInfo())
				web.RespondJSON(ctx, w, err, nil)
				return
			}

			// Sets the cached bp details or loads new bp details into the cache if not present, and into the context
			if ctx, err = LoadDetailsToContext(ctx, authc.JWTClaims{Sub: iamID}); err != nil {
				ravenerrors.Report(err, web.GetRequestContext(ctx).ToRequestInfo())
				web.RespondJSON(ctx, w, err, nil)
				return
			}
			r = r.WithContext(ctx)

			next.ServeHTTP(w, r)
		})
	}
}

