var (
	errIamID = &web.Error{Status: http.StatusBadRequest, Code: "IAM_ID", Desc: "IAM ID is require"}
)

//GetBPDetails returns BPDetails from bi frost
func GetBPDetails(w http.ResponseWriter, r *http.Request) error {
	iamID := r.URL.Query().Get("iam_id")
	if iamID == "" {
		return errIamID
	}

	jwtClaims := authc.JWTClaims{
		Sub: iamID,
	}
	details, err := LoadDetails(r.Context(), jwtClaims, true)
	if err != nil {
		return err
	}
	web.RespondJSON(r.Context(), w, details, nil)
	return nil
}

// Package ami is generated from internal/app/v3/ami/charts_response.json by tools/codegen/v2/struct-json.rb
package ami

// ChartsResponse is toplevel struct
type ChartsResponse struct {
	Unit      string        `json:"unit"`
	GroupedBy string        `json:"grouped_by"`
	History   []HistoryType `json:"history"`
}

// HistoryType is subcomponent
type HistoryType struct {
	Next     bool       `json:"next"`
	Previous bool       `json:"previous"`
	Start    string     `json:"start"`
	End      string     `json:"end"`
	Data     []DataType `json:"data"`
}

// DataType is subcomponent
type DataType struct {
	Date        string  `json:"date"`
	Consumption float64 `json:"consumption"`
}

