import (
	"context"
	"os"
)

// verifyCacheResults verifies whether the cached results belong to the cache key provided
func verifyCacheResults(ctx context.Context, key string, cached Details) bool {
	// Feature toggle to disable cache verification
	if os.Getenv("DISABLE_CACHE_VERIFICATION") == "1" {
		return true
	}

	// If the cached sub value is different from the key, return false
	if cached.JWT.Sub != key {
		return false
	}

	return true
}

